insert into lecciones (numero, fecha, serie, titulo, lectura_biblica, versiculo_central_cita, versiculo_central_texto, introduccion, semestre) values
(1, '2026-07-04', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Las Sagradas Escrituras$t$, NULL, $vc$2 Timoteo 3:16, 17$vc$, $vt$Toda Escritura es inspirada divinamente y útil para enseñar, para redargüir, para corregir, para instituir en justicia, Para que el hombre de Dios sea perfecto, enteramente instruído para toda buena obra.$vt$, $in$Cristo estudiaba las Escrituras y conservaba siempre sus palabras en el corazón como defensa contra la tentación, así también debe todo Cristiano estudiar la palabra de Dios y meditar en ella, para dejar de hacer lo malo.$in$, '2026-2'),
(2, '2026-07-11', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La preexistencia de Cristo$t$, NULL, $vc$Juan 1:1$vc$, $vt$En el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios.$vt$, $in$Verbo o palabra, en Griego logos. El evangelista Juan describe al “Verbo” como un ser Divino, existente desde la Eternidad con el Padre, distinguiéndose sin embargo de él en su calidad de Hijo; creador de todas las cosas, y el cual, llegada la plenitud del tiempo, se hizo carne en medio de los hombres.$in$, '2026-2'),
(3, '2026-07-18', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La importancia de la profecía$t$, NULL, $vc$2 Pedro 1:19$vc$, $vt$Tenemos también la palabra profética más permanente, á la cual hacéis bien de estar atentos como á una antorcha que alumbra en lugar oscuro hasta que el día esclarezca, y el lucero de la mañana salga en vuestros corazones:$vt$, $in$La Escritura profética nos suministra infalible evidencia de que es la voz del Dios vivo, la que habla en los Escritos Sagrados. Una de las señales de su Divinidad la constituye el poder de anunciar el curso de la historia largos siglos antes que los acontecimientos sucedan.$in$, '2026-2'),
(4, '2026-07-25', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Señales de los tiempos$t$, NULL, $vc$Mateo 24:3$vc$, $vt$Y sentándose él en el monte de las Olivas, se llegaron á él los discípulos aparte, diciendo: Dinos, ¿cuándo serán estas cosas, y qué señal habrá de tu venida, y del fin del mundo?$vt$, $in$Al contestar esta pregunta, el Salvador describió los acontecimientos de los últimos tiempos. Ahora los verdaderos Cristianos pueden mirar hacia arriba, sabiendo que su Redención está cerca. (Lucas 21: 28).$in$, '2026-2'),
(5, '2026-08-01', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La segunda venida de Cristo$t$, NULL, $vc$HEBREOS 9:28$vc$, $vt$Así también Cristo fué ofrecido una vez para agotar los pecados de muchos; y la segunda vez, sin pecado, será visto de los que le esperan para salud.$vt$, $in$Esta segunda Venida de Cristo, lo mismo como su primera, fue desde el principio, tema de la profecía. Esto es lo que puso de relieve el apóstol Pedro en el segundo Sermón que de él tenemos registro. En el nuevo testamento se menciona como 318 veces.$in$, '2026-2'),
(6, '2026-08-08', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$El reino de Cristo en el cielo$t$, NULL, $vc$Mateo 24:31$vc$, $vt$Y enviará sus ángeles con gran voz de trompeta, y juntarán sus escogidos de los cuatro vientos, de un cabo del cielo hasta el otro.$vt$, $in$A los justos muertos les es devuelta la vida, y los justos vivos son transformados de su estado mortal en inmortal. Luego todos juntos, con la escolta de los Ángeles, siguen al Salvador hasta las mansiones Celestiales que él ha aparejado en la Jerusalén Celestial.$in$, '2026-2'),
(7, '2026-08-15', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$El reino de Dios en la tierra$t$, NULL, $vc$1 Corintios 15:24$vc$, $vt$Luego el fin; cuando entregará el reino á Dios y al Padre, cuando habrá quitado todo imperio, y toda potencia y potestad.$vt$, $in$La promesa del Evangelio de Salvación no sólo es que obtengamos la vida eterna por la Fe, sino que también recibamos herencia Eterna de la tierra hecha nueva en cumplimiento del plan que tenía el Creador cuando hizo este mundo para que fuese la patria del hombre.$in$, '2026-2'),
(8, '2026-08-22', NULL, $t$La doctrina de las Sagradas Escrituras. El juicio$t$, NULL, $vc$Hechos 17:30, 31$vc$, $vt$Empero Dios, habiendo disimulado los tiempos de esta ignorancia, ahora denuncia á todos los hombres en todos los lugares que se arrepientan: Por cuanto ha establecido un día, en el cual ha de juzgar al mundo con justicia, por aquel varón al cual determinó; dando fe á todos con haberle levantado de los muertos.$vt$, $in$Durante este juicio, tanto los justos como los impíos están todavía en la tumba. El registro de la vida de cada uno de los justos se halla anotado en los libros del cielo, y de acuerdo con este registro es juzgado su carácter, pues sus obras son conocidas.$in$, '2026-2'),
(9, '2026-08-29', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La Ley de Dios$t$, NULL, $vc$Mateo 5:17-19$vc$, $vt$No penséis que he venido para abrogar la ley ó los profetas: no he venido para abrogar, sino á cumplir. Porque de cierto os digo, que hasta que perezca el cielo y la tierra, ni una jota ni un tilde perecerá de la ley, hasta que todas las cosas sean hechas. De manera que cualquiera que infringiere uno de estos mandamientos muy pequeños, y así enseñare á los hombres, muy pequeño será llamado en el reino de los cielos: mas cualquiera que hiciere y enseñare, éste será llamado grande en el reino de los cielos.$vt$, $in$Son muchos religiosos que se olvidan de la Ley de Dios. Son muchos los que se extrañan de que, después de la Salvación de Cristo, se menciona la Ley y el juicio. Quisieran eliminar por completo los Mandamientos de Dios. Pero Cristo dijo que no vino para abrogar la ley.$in$, '2026-2'),
(10, '2026-09-05', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La ley ceremonial$t$, NULL, $vc$Gálatas 3:19$vc$, $vt$¿Pues de qué sirve la ley? Fué puesta por causa de las rebeliones, hasta que viniese la simiente á quien fué hecha la promesa, ordenada aquélla por los ángeles en la mano de un mediador.$vt$, $in$Las Sagradas Escrituras nos presentan una ley de ritos, sacrificios y ceremonias, la cual es conocida como Ley Ceremonial. Fue dada por causa de la desobediencia del pueblo judío a la ley moral, o sea; a la de los diez Mandamientos, cuya transgresión es pecado. (1 Juan 3:4).$in$, '2026-2'),
(11, '2026-09-12', $s$La doctrina pura de las Sagradas Escrituras,$s$, $t$Dos leyes: la moral y la ceremonial$t$, NULL, $vc$GÉNESIS 4:3-5$vc$, $vt$Y aconteció andando el tiempo, que Caín trajo del fruto de la tierra una ofrenda á Jehová. Y Abel trajo también de los primogénitos de sus ovejas, y de su grosura. Y miró Jehová con agrado á Abel y á su ofrenda; Mas no miró propicio á Caín y á la ofrenda suya. Y ensañóse Caín en gran manera, y decayó su semblante.$vt$, $in$Los sacrificios dan testimonio del sentimiento que el hombre tenía de su culpa y de su alejamiento de Dios. Después el sistema de sacrificios, con sus ritos y ceremonias señalaban a Cristo.$in$, '2026-2'),
(12, '2026-09-19', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$¿Qué fue abolido por Cristo?$t$, NULL, $vc$Colosenses 2:14$vc$, $vt$Rayendo la cédula de los ritos que nos era contraria, que era contra nosotros, quitándola de en medio y enclavándola en la cruz;$vt$, $in$Cuando Cristo murió, el sistema de sacrificios, ceremonias, fiestas, sacerdocio, diezmos, primicias y culto en general, acabó; pues de haber continuado después que Cristo había muerto en la cruz, habría sido un insulto terrible al Cordero de Dios.$in$, '2026-2'),
(13, '2026-09-26', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$El Santuario o el plan de salvación$t$, NULL, $vc$Hebreos 8:5$vc$, $vt$Los cuales sirven de bosquejo y sombra de las cosas celestiales, como fué respondido á Moisés cuando había de acabar el tabernáculo: Mira, dice, haz todas las cosas conforme al dechado que te ha sido mostrado en el monte.$vt$, $in$El servicio sacerdotal del Santuario terrenal, o Templo, en los días de Israel natural, era tipo de la obra de Cristo, nuestro sumo Sacerdote en el Templo Celestial. Los sacerdotes terrenales servían según el bosquejo y sombra de las cosas Celestiales.$in$, '2026-2'),
(14, '2026-10-03', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$El día del Señor$t$, NULL, $vc$Marcos 2:27$vc$, $vt$También les dijo: El sábado por causa del hombre es hecho; no el hombre por causa del sábado.$vt$, $in$Todas las cosas fueron hechas por Cristo, y sin él nada de lo que es, fue hecho, y el Sábado fue una de las cosas hechas por Él. Siendo esto así, el Sábado es día del Señor.$in$, '2026-2'),
(15, '2026-10-10', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Cristo y el Sábado$t$, NULL, $vc$Apocalipsis 1:10$vc$, $vt$Yo fuí en el Espíritu en el día del Señor, y oí detrás de mí una gran voz como de trompeta,$vt$, $in$El Señor tiene un día particular que han de guardar los Cristianos. El día Séptimo es el que Cristo guardó como una costumbre y así también todos los que recibieron su Evangelio.$in$, '2026-2'),
(16, '2026-10-17', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$¿Quién es el culpable del cambio del día del Señor?$t$, NULL, $vc$Daniel 7:25$vc$, $vt$Y hablará palabras contra el Altísimo, y á los santos del Altísimo quebrantará, y pensará en mudar los tiempos y la ley: y entregados serán en su mano hasta tiempo, y tiempos, y el medio de un tiempo.$vt$, $in$Se ha atribuido el papado los nombres y la autoridad que pertenecen a Cristo, y se hizo culpable de perseguir a los fieles, e intentar cambiar la Ley de Dios, Los Diez Mandamientos.$in$, '2026-2'),
(17, '2026-10-24', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La marca de la bestia$t$, NULL, $vc$Apocalipsis 13:16, 17; Apocalipsis 14:9, 10$vc$, $vt$Y hacía que á todos, á los pequeños y grandes, ricos y pobres, libres y siervos, se pusiese una marca en su mano derecha, ó en sus frentes: Y que ninguno pudiese comprar ó vender, sino el que tuviera la señal, ó el nombre de la bestia, ó el número de su nombre. Y el tercer ángel los siguió, diciendo en alta voz: Si alguno adora á la bestia y á su imagen, y toma la señal en su frente, ó en su mano, Este también beberá del vino de la ira de Dios, el cual está echado puro en el cáliz de su ira; y será atormentado con fuego y azufre delante de los santos ángeles, y delante del Cordero:$vt$, $in$La marca de la bestia es una falsificación del sello de Dios, que una persona puede llevar en la frente o en la mano. La marca de la bestia es el domingo, la marca de Dios es el Sábado.$in$, '2026-2'),
(18, '2026-10-31', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Las siete postreras plagas$t$, NULL, $vc$Salmos 91:10$vc$, $vt$No te sobrevendrá mal, ni plaga tocará tu morada.$vt$, $in$El señor advierte a su pueblo que ninguna de las plagas que vendrán como castigos terribles a los infieles, tocará su morada.
