insert into lecciones_preguntas (leccion_id, orden, pregunta, citas, nota)
insert into citas_texto (cita, texto) values
($c$1 Corintios 11:1$c$, $x$Sed imitadores de mí, así como yo de Cristo.$x$),
($c$1 Corintios 12:13-27$c$, $x$13 Porque por un Espíritu somos todos bautizados en un cuerpo, ora Judíos ó Griegos, ora siervos ó libres; y todos hemos bebido de un mismo Espíritu.  14 Pues ni tampoco el cuerpo es un miembro, sino muchos.  15 Si dijere el pie: Porque no soy mano, no soy del cuerpo: ¿por eso no será del cuerpo?  16 Y si dijere la oreja: Porque no soy ojo, no soy del cuerpo: ¿por eso no será del cuerpo?  17 Si todo el cuerpo fuese ojo, ¿dónde estaría el oído? Si todo fuese oído, ¿dónde estaría el olfato?  18 Mas ahora Dios ha colocado los miembros cada uno de ellos en el cuerpo, como quiso.  19 Que si todos fueran un miembro, ¿dónde estuviera el cuerpo?  20 Mas ahora muchos miembros son á la verdad, empero un cuerpo.  21 Ni el ojo puede decir á la mano: No te he menester: ni asimismo la cabeza á los pies: No tengo necesidad de vosotros.  22 Antes, mucho más los miembros del cuerpo que parecen más flacos, son necesarios;  23 Y á aquellos del cuerpo que estimamos ser más viles, á éstos vestimos más honrosamente; y los que en nosotros son menos honestos, tienen más compostura.  24 Porque los que en nosotros son más honestos, no tienen necesidad: mas Dios ordenó el cuerpo, dando más abundante honor al que le faltaba;  25 Para que no haya desavenencia en el cuerpo, sino que los miembros todos se interesen los unos por los otros.  26 Por manera que si un miembro padece, todos los miembros á una se duelen; y si un miembro es honrado, todos los miembros á una se gozan.  27 Pues vosotros sois el cuerpo de Cristo, y miembros en parte.$x$),
($c$1 Corintios 14:33$c$, $x$Porque Dios no es Dios de disensión, sino de paz; como en todas las iglesias de los santos.$x$),
($c$1 Corintios 14:40$c$, $x$Empero hágase todo decentemente y con orden.$x$),
($c$1 Corintios 15:16-18$c$, $x$16 Porque si los muertos no resucitan, tampoco Cristo resucitó:  17 Y si Cristo no resucitó, vuestra fe es vana; aun estáis en vuestros pecados.  18 Entonces también los que durmieron en Cristo son perdidos.$x$),
($c$1 Corintios 15:49-53$c$, $x$49 Y como trajimos la imagen del terreno, traeremos también la imagen del celestial.  50 Esto empero digo, hermanos: que la carne y la sangre no pueden heredar el reino de Dios; ni la corrupción hereda la incorrupción.  51 He aquí, os digo un misterio: Todos ciertamente no dormiremos, mas todos seremos transformados,  52 En un momento, en un abrir de ojo, á la final trompeta; porque será tocada la trompeta, y los muertos serán levantados sin corrupción, y nosotros seremos transformados.  53 Porque es menester que esto corruptible sea vestido de incorrupción, y esto mortal sea vestido de inmortalidad.$x$),
($c$1 Corintios 15:51-53$c$, $x$51 He aquí, os digo un misterio: Todos ciertamente no dormiremos, mas todos seremos transformados,  52 En un momento, en un abrir de ojo, á la final trompeta; porque será tocada la trompeta, y los muertos serán levantados sin corrupción, y nosotros seremos transformados.  53 Porque es menester que esto corruptible sea vestido de incorrupción, y esto mortal sea vestido de inmortalidad.$x$),
($c$1 Corintios 15:51-55$c$, $x$51 He aquí, os digo un misterio: Todos ciertamente no dormiremos, mas todos seremos transformados,  52 En un momento, en un abrir de ojo, á la final trompeta; porque será tocada la trompeta, y los muertos serán levantados sin corrupción, y nosotros seremos transformados.  53 Porque es menester que esto corruptible sea vestido de incorrupción, y esto mortal sea vestido de inmortalidad.  54 Y cuando esto corruptible fuere vestido de incorrupción, y esto mortal fuere vestido de inmortalidad, entonces se efectuará la palabra que está escrita: Sorbida es la muerte con victoria.  55 ¿Dónde está, oh muerte, tu aguijón? ¿dónde, oh sepulcro, tu victoria?$x$),
($c$1 Corintios 15:54$c$, $x$Y cuando esto corruptible fuere vestido de incorrupción, y esto mortal fuere vestido de inmortalidad, entonces se efectuará la palabra que está escrita: Sorbida es la muerte con victoria.$x$),
($c$1 Corintios 15:57$c$, $x$Mas á Dios gracias, que nos da la victoria por el Señor nuestro Jesucristo.$x$),
($c$1 Corintios 4:9-13$c$, $x$9 Porque á lo que pienso, Dios nos ha mostrado á nosotros los apóstoles por los postreros, como á sentenciados á muerte: porque somos hechos espectáculo al mundo, y á los ángeles, y á los hombres.  10 Nosotros necios por amor de Cristo, y vosotros prudentes en Cristo; nosotros flacos, y vosotros fuertes; vosotros nobles, y nosotros viles.  11 Hasta esta hora hambreamos, y tenemos sed, y estamos desnudos, y somos heridos de golpes, y andamos vagabundos;  12 Y trabajamos, obrando con nuestras manos: nos maldicen, y bendecimos: padecemos persecución, y sufrimos:  13 Somos blasfemados, y rogamos: hemos venido á ser como la hez del mundo, el desecho de todos hasta ahora.$x$),
($c$1 Juan 2:4$c$, $x$El que dice, Yo le he conocido, y no guarda sus mandamientos, el tal es mentiroso, y no hay verdad en él;$x$),
($c$1 Juan 2:6$c$, $x$El que dice que está en él, debe andar como él anduvo.$x$),
($c$1 Juan 3:2$c$, $x$Muy amados, ahora somos hijos de Dios, y aun no se ha manifestado lo que hemos de ser; pero sabemos que cuando él apareciere, seremos semejantes á él, porque le veremos como él es.$x$),
($c$1 Juan 3:4$c$, $x$Cualquiera que hace pecado, traspasa también la ley; pues el pecado es transgresión de la ley.$x$),
($c$1 Juan 3:8$c$, $x$El que hace pecado, es del diablo; porque el diablo peca desde el principio. Para esto apareció el Hijo de Dios, para deshacer las obras del diablo.$x$),
($c$1 Pedro 2:21$c$, $x$Porque para esto sois llamados; pues que también Cristo padeció por nosotros, dejándonos ejemplo, para que vosotros sigáis sus pisadas:$x$),
($c$1 Pedro 2:5-8$c$, $x$5 Vosotros también, como piedras vivas, sed edificados una casa espiritual, y un sacerdocio santo, para ofrecer sacrificios espirituales, agradables á Dios por Jesucristo.  6 Por lo cual también contiene la Escritura: He aquí, pongo en Sión la principal piedra del ángulo, escogida, preciosa; y el que creyere en ella, no será confundido.  7 Ella es pues honor á vosotros que creéis: mas para los desobedientes, la piedra que los edificadores reprobaron, ésta fué hecha la cabeza del ángulo;  8 Y Piedra de tropiezo, y roca de escándalo á aquellos que tropiezan en la palabra, siendo desobedientes; para lo cual fueron también ordenados.$x$),
($c$1 Pedro 5:1-4$c$, $x$1 Ruego á los ancianos que están entre vosotros, yo anciano también con ellos, y testigo de las aflicciones de Cristo, que soy también participante de la gloria que ha de ser revelada:  2 Apacentad la grey de Dios que está entre vosotros, teniendo cuidado de ella, no por fuerza, sino voluntariamente; no por ganancia deshonesta, sino de un ánimo pronto;  3 Y no como teniendo señorío sobre las heredades del Señor, sino siendo dechados de la grey.  4 Y cuando apareciere el Príncipe de los pastores, vosotros recibiréis la corona incorruptible de gloria.$x$),
($c$1 Pedro 5:8, 9$c$, $x$8 Sed templados, y velad; porque vuestro adversario el diablo, cual león rugiente, anda alrededor buscando á quien devore:  9 Al cual resistid firmes en la fe, sabiendo que las mismas aflicciones han de ser cumplidas en la compañía de vuestros hermanos que están en el mundo.$x$),
($c$1 Tesalonicenses 2:10-12$c$, $x$10 Vosotros sois testigos, y Dios, de cuán santa y justa é irreprensiblemente nos condujimos con vosotros que creísteis:  11 Así como sabéis de qué modo exhortábamos y consolábamos á cada uno de vosotros, como el padre á sus hijos,  12 Y os protestábamos que anduvieseis como es digno de Dios, que os llamó á su reino y gloria.$x$),
($c$1 Tesalonicenses 4:16$c$, $x$Porque el mismo Señor con aclamación, con voz de arcángel, y con trompeta de Dios, descenderá del cielo; y los muertos en Cristo resucitarán primero:$x$),
($c$1 Tesalonicenses 4:16, 17$c$, $x$16 Porque el mismo Señor con aclamación, con voz de arcángel, y con trompeta de Dios, descenderá del cielo; y los muertos en Cristo resucitarán primero:  17 Luego nosotros, los que vivimos, los que quedamos, juntamente con ellos seremos arrebatados en las nubes á recibir al Señor en el aire, y así estaremos siempre con el Señor.$x$),
($c$1 Tesalonicenses 4:17$c$, $x$Luego nosotros, los que vivimos, los que quedamos, juntamente con ellos seremos arrebatados en las nubes á recibir al Señor en el aire, y así estaremos siempre con el Señor.$x$),
($c$1 Tesalonicenses 4:17, 18$c$, $x$17 Luego nosotros, los que vivimos, los que quedamos, juntamente con ellos seremos arrebatados en las nubes á recibir al Señor en el aire, y así estaremos siempre con el Señor.  18 Por tanto, consolaos los unos á los otros en estas palabras.$x$),
($c$1 Tesalonicenses 5:1-4$c$, $x$1 Empero acerca de los tiempos y de los momentos, no tenéis, hermanos, necesidad de que yo os escriba:  2 Porque vosotros sabéis bien, que el día del Señor vendrá así como ladrón de noche,  3 Que cuando dirán, Paz y seguridad, entonces vendrá sobre ellos destrucción de repente, como los dolores á la mujer preñada; y no escaparán.  4 Mas vosotros, hermanos, no estáis en tinieblas, para que aquel día os sobrecoja como ladrón;$x$),
($c$1 Timoteo 1:17$c$, $x$Por tanto, al Rey de siglos, inmortal, invisible, al solo sabio Dios sea honor y gloria por los siglos de los siglos. Amén.$x$),
($c$1 Timoteo 2:12$c$, $x$Porque no permito á la mujer enseñar, ni tomar autoridad sobre el hombre, sino estar en silencio.$x$),
($c$1 Timoteo 5:10, 11$c$, $x$10 Que tenga testimonio en buenas obras; si crió hijos; si ha ejercitado la hospitalidad; si ha lavado los pies de los santos; si ha socorrido á los afligidos; si ha seguido toda buena obra.  11 Pero viudas más jóvenes no admitas: porque después de hacerse licenciosas contra Cristo, quieren casarse.$x$),
($c$1 Timoteo 5:17, 18$c$, $x$17 Los ancianos que gobiernan bien, sean tenidos por dignos de doblada honra; mayormente los que trabajan en predicar y enseñar.  18 Porque la Escritura dice: No embozarás al buey que trilla; y: Digno es el obrero de su jornal.$x$),
($c$1 Timoteo 6:15, 16$c$, $x$15 La cual á su tiempo mostrará el Bienaventurado y solo Poderoso, Rey de reyes, y Señor de señores;  16 Quien sólo tiene inmortalidad, que habita en luz inaccesible; á quien ninguno de los hombres ha visto ni puede ver: al cual sea la honra y el imperio sempiterno. Amén.$x$),
($c$1 Timoteo 6:7, 18$c$, $x$7 Porque nada hemos traído á este mundo, y sin duda nada podremos sacar.  18 Que hagan bien, que sean ricos en buenas obras, dadivosos, que con facilidad comuniquen;$x$),
($c$2 Corintios 12:2-4$c$, $x$2 Conozco á un hombre en Cristo, que hace catorce años (si en el cuerpo, no lo sé; si fuera del cuerpo, no lo sé: Dios lo sabe) fué arrebatado hasta el tercer cielo.  3 Y conozco tal hombre, (si en el cuerpo, ó fuera del cuerpo, no lo sé: Dios lo sabe,)  4 Que fué arrebatado al paraíso, donde oyó palabras secretas que el hombre no puede decir.$x$),
($c$2 Corintios 2:17$c$, $x$Porque no somos como muchos, mercaderes falsos de la palabra de Dios: antes con sinceridad, como de Dios, delante de Dios, hablamos en Cristo.$x$),
($c$2 Corintios 5:10$c$, $x$Porque es menester que todos nosotros parezcamos ante el tribunal de Cristo, para que cada uno reciba según lo que hubiere hecho por medio del cuerpo, ora sea bueno ó malo.$x$),
($c$2 Pedro 1:16-19$c$, $x$16 Porque no os hemos dado á conocer la potencia y la venida de nuestro Señor Jesucristo, siguiendo fábulas por arte compuestas; sino como habiendo con nuestros propios ojos visto su majestad.  17 Porque él había recibido de Dios Padre honra y gloria, cuando una tal voz fué á él enviada de la magnífica gloria: Este es el amado Hijo mío, en el cual yo me he agradado.  18 Y nosotros oímos esta voz enviada del cielo, cuando estábamos juntamente con él en el monte santo.  19 Tenemos también la palabra profética más permanente, á la cual hacéis bien de estar atentos como á una antorcha que alumbra en lugar oscuro hasta que el día esclarezca, y el lucero de la mañana salga en vuestros corazones:$x$),
($c$2 Pedro 1:21$c$, $x$Porque la profecía no fué en los tiempos pasados traída por voluntad humana, sino los santos hombres de Dios hablaron siendo inspirados del Espíritu Santo.$x$),
($c$2 Pedro 2:4$c$, $x$Porque si Dios no perdonó á los ángeles que habían pecado, sino que habiéndolos despeñado en el infierno con cadenas de oscuridad, los entregó para ser reservados al juicio;$x$),
($c$2 Pedro 3:13$c$, $x$Bien que esperamos cielos nuevos y tierra nueva, según sus promesas, en los cuales mora la justicia.$x$),
($c$2 Tesalonicenses 1:7-9$c$, $x$7 Y á vosotros, que sois atribulados, dar reposo con nosotros, cuando se manifestará el Señor Jesús del cielo con los ángeles de su potencia,  8 En llama de fuego, para dar el pago á los que no conocieron á Dios, ni obedecen al evangelio de nuestro Señor Jesucristo;  9 Los cuales serán castigados de eterna perdición por la presencia del Señor, y por la gloria de su potencia,$x$),
($c$2 Tesalonicenses 2:1, 2$c$, $x$1 Empero os rogamos, hermanos, cuanto á la venida de nuestro Señor Jesucristo, y nuestro recogimiento á él,  2 Que no os mováis fácilmente de vuestro sentimiento, ni os conturbéis ni por espíritu, ni por palabra, ni por carta como nuestra, como que el día del Señor esté cerca.$x$),
($c$2 Timoteo 1:10$c$, $x$Mas ahora es manifestada por la aparición de nuestro Salvador Jesucristo, el cual quitó la muerte, y sacó á la luz la vida y la inmortalidad por el evangelio;$x$),
($c$2 Timoteo 3:12$c$, $x$Y también todos los que quieren vivir píamente en Cristo Jesús, padecerán persecución.$x$),
($c$2 Timoteo 3:13$c$, $x$Mas los malos hombres y los engañadores, irán de mal en peor, engañando y siendo engañados.$x$),
($c$2 Timoteo 3:16$c$, $x$Toda Escritura es inspirada divinamente y útil para enseñar, para redargüir, para corregir, para instituir en justicia,$x$),
($c$2 Timoteo 3:16, 17$c$, $x$16 Toda Escritura es inspirada divinamente y útil para enseñar, para redargüir, para corregir, para instituir en justicia,  17 Para que el hombre de Dios sea perfecto, enteramente instruído para toda buena obra.$x$),
($c$2 Timoteo 4:1, 2$c$, $x$1 Requiero yo pues delante de Dios, y del Señor Jesucristo, que ha de juzgar á los vivos y los muertos en su manifestación y en su reino,  2 Que prediques la palabra; que instes á tiempo y fuera de tiempo; redarguye, reprende, exhorta con toda paciencia y doctrina.$x$),
($c$2 Timoteo 4:18$c$, $x$Y el Señor me librará de toda obra mala, y me preservará para su reino celestial: al cual sea gloria por los siglos de los siglos. Amén.$x$),
($c$2 Timoteo 4:3, 4$c$, $x$3 Porque vendrá tiempo cuando no sufrirán la sana doctrina; antes, teniendo comezón de oir, se amontonarán maestros conforme á sus concupiscencias,  4 Y apartarán de la verdad el oído, y se volverán á las fábulas.$x$),
($c$2 Timoteo 4:6-8$c$, $x$6 Porque yo ya estoy para ser ofrecido, y el tiempo de mi partida está cercano.  7 He peleado la buena batalla, he acabado la carrera, he guardado la fe.  8 Por lo demás, me está guardada la corona de justicia, la cual me dará el Señor, juez justo, en aquel día; y no sólo á mí, sino también á todos los que aman su venida.$x$),
($c$2 corintios 6:17, 18$c$, $x$17 Por lo cual salid de en medio de ellos, y apartaos, dice el Señor, y no toquéis lo inmundo; y yo os recibiré,  18 Y seré á vosotros Padre, y vosotros me seréis á mí hijos é hijas, dice el Señor Todopoderoso.$x$),
($c$Amos 3:7$c$, $x$Porque no hará nada el Señor Jehová, sin que revele su secreto á sus siervos los profetas.$x$),
($c$Amos 8:4-6$c$, $x$4 Oid esto, los que tragáis á los menesterosos, y arruináis los pobres de la tierra,  5 Diciendo: ¿Cuándo pasará el mes, y venderemos el trigo; y la semana, y abriremos los alfolíes del pan, y achicaremos la medida, y engrandeceremos el precio, y falsearemos el peso engañoso;  6 Para comprar los pobres por dinero, y los necesitados por un par de zapatos, y venderemos las aechaduras del trigo?$x$),
($c$Apoc. 1:7$c$, $x$He aquí que viene con las nubes, y todo ojo le verá, y los que le traspasaron; y todos los linajes de la tierra se lamentarán sobre él. Así sea. Amén.$x$),
($c$Apocalipsis  21:1-3, 10, 11$c$, $x$1 Y vi un cielo nuevo, y una tierra nueva: porque el primer cielo y la primera tierra se fueron, y el mar ya no es.  2 Y yo Juan vi la santa ciudad, Jerusalem nueva, que descendía del cielo, de Dios, dispuesta como una esposa ataviada para su marido.  3 Y oí una gran voz del cielo que decía: He aquí el tabernáculo de Dios con los hombres, y morará con ellos; y ellos serán su pueblo, y el mismo Dios será su Dios con ellos.  10 Y llevóme en Espíritu á un grande y alto monte, y me mostró la grande ciudad santa de Jerusalem, que descendía del cielo de Dios,  11 Teniendo la claridad de Dios: y su luz era semejante á una piedra preciosísima, como piedra de jaspe, resplandeciente como cristal.$x$),
($c$Apocalipsis 11:19$c$, $x$Y el templo de Dios fué abierto en el cielo, y el arca de su testamento fué vista en su templo. Y fueron hechos relámpagos y voces y truenos y terremotos y grande granizo.$x$),
($c$Apocalipsis 12:17$c$, $x$Entonces el dragón fué airado contra la mujer; y se fué á hacer guerra contra los otros de la simiente de ella, los cuales guardan los mandamientos de Dios, y tienen el testimonio de Jesucristo.$x$),
($c$Apocalipsis 12:7-9$c$, $x$7 Y fué hecha una grande batalla en el cielo: Miguel y sus ángeles lidiaban contra el dragón; y lidiaba el dragón y sus ángeles,  8 Y no prevalecieron, ni su lugar fué más hallado en el cielo.  9 Y fué lanzado fuera aquel gran dragón, la serpiente antigua, que se llama Diablo y Satanás, el cual engaña á todo el mundo; fué arrojado en tierra, y sus ángeles fueron arrojados con él.$x$),
($c$Apocalipsis 12:9$c$, $x$Y fué lanzado fuera aquel gran dragón, la serpiente antigua, que se llama Diablo y Satanás, el cual engaña á todo el mundo; fué arrojado en tierra, y sus ángeles fueron arrojados con él.$x$),
($c$Apocalipsis 14:12$c$, $x$Aquí está la paciencia de los santos; aquí están los que guardan los mandamientos de Dios, y la fe de Jesús.$x$),
($c$Apocalipsis 14:6, 7$c$, $x$6 Y vi otro ángel volar por en medio del cielo, que tenía el evangelio eterno para predicarlo á los que moran en la tierra, y á toda nación y tribu y lengua y pueblo,  7 Diciendo en alta voz: Temed á Dios, y dadle honra; porque la hora de su juicio es venida; y adorad á aquel que ha hecho el cielo y la tierra y el mar y las fuentes de las aguas.$x$),
($c$Apocalipsis 14:9, 10$c$, $x$9 Y el tercer ángel los siguió, diciendo en alta voz: Si alguno adora á la bestia y á su imagen, y toma la señal en su frente, ó en su mano,  10 Este también beberá del vino de la ira de Dios, el cual está echado puro en el cáliz de su ira; y será atormentado con fuego y azufre delante de los santos ángeles, y delante del Cordero:$x$)
insert into citas_texto (cita, texto) values
($c$Apocalipsis 15:1$c$, $x$Y vi otra señal en el cielo, grande y admirable, que era siete ángeles que tenían las siete plagas postreras; porque en ellas es consumada la ira de Dios.$x$),
($c$Apocalipsis 15:2, 3$c$, $x$2 Y vi así como un mar de vidrio mezclado con fuego; y los que habían alcanzado la victoria de la bestia, y de su imagen, y de su señal, y del número de su nombre, estar sobre el mar de vidrio, teniendo las arpas de Dios.  3 Y cantan el cántico de Moisés siervo de Dios, y el cántico del Cordero, diciendo: Grandes y maravillosas son tus obras, Señor Dios Todopoderoso; justos y verdaderos son tus caminos, Rey de los santos.$x$),
($c$Apocalipsis 15:3, 4$c$, $x$3 Y cantan el cántico de Moisés siervo de Dios, y el cántico del Cordero, diciendo: Grandes y maravillosas son tus obras, Señor Dios Todopoderoso; justos y verdaderos son tus caminos, Rey de los santos.  4 ¿Quién no te temerá, oh Señor, y engrandecerá tu nombre? porque tú sólo eres santo; por lo cual todas las naciones vendrán, y adorarán delante de ti, porque tus juicios son manifestados.$x$),
($c$Apocalipsis 15:5$c$, $x$Y después de estas cosas miré, y he aquí el templo del tabernáculo del testimonio fué abierto en el cielo;$x$),
($c$Apocalipsis 16:10$c$, $x$Y el quinto ángel derramó su copa sobre la silla de la bestia; y su reino se hizo tenebroso, y se mordían sus lenguas de dolor;$x$),
($c$Apocalipsis 16:12$c$, $x$Y el sexto ángel derramó su copa sobre el gran río Eufrates; y el agua de él se secó, para que fuese preparado el camino de los reyes del Oriente.$x$),
($c$Apocalipsis 16:13, 14$c$, $x$13 Y vi salir de la boca del dragón, y de la boca de la bestia, y de la boca del falso profeta, tres espíritus inmundos á manera de ranas:  14 Porque son espíritus de demonios, que hacen señales, para ir á los reyes de la tierra y de todo el mundo, para congregarlos para la batalla de aquel gran día del Dios Todopoderoso.$x$),
($c$Apocalipsis 16:13-16$c$, $x$13 Y vi salir de la boca del dragón, y de la boca de la bestia, y de la boca del falso profeta, tres espíritus inmundos á manera de ranas:  14 Porque son espíritus de demonios, que hacen señales, para ir á los reyes de la tierra y de todo el mundo, para congregarlos para la batalla de aquel gran día del Dios Todopoderoso.  15 He aquí, yo vengo como ladrón. Bienaventurado el que vela, y guarda sus vestiduras, para que no ande desnudo, y vean su vergüenza.  16 Y los congregó en el lugar que en hebreo se llama Armagedón.$x$),
($c$Apocalipsis 16:15$c$, $x$He aquí, yo vengo como ladrón. Bienaventurado el que vela, y guarda sus vestiduras, para que no ande desnudo, y vean su vergüenza.$x$),
($c$Apocalipsis 16:17-19$c$, $x$17 Y el séptimo ángel derramó su copa por el aire; y salió una grande voz del templo del cielo, del trono, diciendo: Hecho es.  18 Entonces fueron hechos relámpagos y voces y truenos; y hubo un gran temblor de tierra, un terremoto tan grande, cual no fué jamás desde que los hombres han estado sobre la tierra.  19 Y la ciudad grande fué partida en tres partes, y las ciudades de las naciones cayeron; y la grande Babilonia vino en memoria delante de Dios, para darle el cáliz del vino del furor de su ira.$x$),
($c$Apocalipsis 16:2$c$, $x$Y fué el primero, y derramó su copa sobre la tierra; y vino una plaga mala y dañosa sobre los hombres que tenían la señal de la bestia, y sobre los que adoraban su imagen.$x$),
($c$Apocalipsis 16:21$c$, $x$Y cayó del cielo sobre los hombres un grande granizo como del peso de un talento: y los hombres blasfemaron de Dios por la plaga del granizo; porque su plaga fué muy grande.$x$),
($c$Apocalipsis 16:3$c$, $x$Y el segundo ángel derramó su copa sobre el mar, y se convirtió en sangre como de un muerto; y toda alma viviente fué muerta en el mar.$x$),
($c$Apocalipsis 16:4$c$, $x$Y el tercer ángel derramó su copa sobre los ríos, y sobre las fuentes de las aguas, y se convirtieron en sangre.$x$),
($c$Apocalipsis 16:4, 23$c$, $x$4 Y el tercer ángel derramó su copa sobre los ríos, y sobre las fuentes de las aguas, y se convirtieron en sangre.$x$),
($c$Apocalipsis 16:6$c$, $x$Porque ellos derramaron la sangre de los santos y de los profetas, también tú les has dado á beber sangre; pues lo merecen.$x$),
($c$Apocalipsis 16:8$c$, $x$Y el cuarto ángel derramó su copa sobre el sol; y le fué dado quemar á los hombres con fuego.$x$),
($c$Apocalipsis 16:9$c$, $x$Y los hombres se quemaron con el grande calor, y blasfemaron el nombre de Dios, que tiene potestad sobre estas plagas, y no se arrepintieron para darle gloria.$x$),
($c$Apocalipsis 18:11, 23$c$, $x$11 Y los mercaderes de la tierra lloran y se lamentan sobre ella, porque ninguno compra más sus mercaderías:  23 Y luz de antorcha no alumbrará más en ti; y voz de esposo ni de esposa no será más en ti oída; porque tus mercaderes eran los magnates de la tierra; porque en tus hechicerías todas las gentes han errado.$x$),
($c$Apocalipsis 18:4, 5$c$, $x$4 Y oí otra voz del cielo, que decía: Salid de ella, pueblo mío, porque no seáis participantes de sus pecados, y que no recibáis de sus plagas;  5 Porque sus pecados han llegado hasta el cielo, y Dios se ha acordado de sus maldades.$x$),
($c$Apocalipsis 1:1$c$, $x$La revelación de Jesucristo, que Dios le dió, para manifestar á sus siervos las cosas que deben suceder presto; y la declaró, enviándola por su ángel á Juan su siervo,$x$),
($c$Apocalipsis 1:10$c$, $x$Yo fuí en el Espíritu en el día del Señor, y oí detrás de mí una gran voz como de trompeta,$x$),
($c$Apocalipsis 1:12, 13$c$, $x$12 Y me volví á ver la voz que hablaba conmigo: y vuelto, vi siete candeleros de oro;  13 Y en medio de los siete candeleros, uno semejante al Hijo del hombre, vestido de una ropa que llegaba hasta los pies, y ceñido por los pechos con una cinta de oro.$x$),
($c$Apocalipsis 1:3$c$, $x$Bienaventurado el que lee, y los que oyen las palabras de esta profecía, y guardan las cosas en ella escritas: porque el tiempo está cerca.$x$),
($c$Apocalipsis 20:11-15$c$, $x$11 Y vi un gran trono blanco y al que estaba sentado sobre él, de delante del cual huyó la tierra y el cielo; y no fué hallado el lugar de ellos.  12 Y vi los muertos, grandes y pequeños, que estaban delante de Dios; y los libros fueron abiertos: y otro libro fué abierto, el cual es de la vida: y fueron juzgados los muertos por las cosas que estaban escritas en los libros, según sus obras.  13 Y el mar dió los muertos que estaban en él; y la muerte y el infierno dieron los muertos que estaban en ellos; y fué hecho juicio de cada uno según sus obras.  14 Y el infierno y la muerte fueron lanzados en el lago de fuego. Esta es la muerte segunda.  15 Y el que no fué hallado escrito en el libro de la vida, fué lanzado en el lago de fuego.$x$),
($c$Apocalipsis 20:12$c$, $x$Y vi los muertos, grandes y pequeños, que estaban delante de Dios; y los libros fueron abiertos: y otro libro fué abierto, el cual es de la vida: y fueron juzgados los muertos por las cosas que estaban escritas en los libros, según sus obras.$x$),
($c$Apocalipsis 20:2$c$, $x$Y prendió al dragón, aquella serpiente antigua, que es el Diablo y Satanás, y le ató por mil años;$x$),
($c$Apocalipsis 20:4, 5$c$, $x$4 Y vi tronos, y se sentaron sobre ellos, y les fué dado juicio; y vi las almas de los degollados por el testimonio de Jesús, y por la palabra de Dios, y que no habían adorado la bestia, ni á su imagen, y que no recibieron la señal en sus frentes, ni en sus manos; y vivieron y reinaron con Cristo mil años.  5 Mas los otros muertos no tornaron á vivir hasta que sean cumplidos mil años. Esta es la primera resurrección.$x$),
($c$Apocalipsis 20:4-7$c$, $x$4 Y vi tronos, y se sentaron sobre ellos, y les fué dado juicio; y vi las almas de los degollados por el testimonio de Jesús, y por la palabra de Dios, y que no habían adorado la bestia, ni á su imagen, y que no recibieron la señal en sus frentes, ni en sus manos; y vivieron y reinaron con Cristo mil años.  5 Mas los otros muertos no tornaron á vivir hasta que sean cumplidos mil años. Esta es la primera resurrección.  6 Bienaventurado y santo el que tiene parte en la primera resurrección: la segunda muerte no tiene potestad en éstos; antes serán sacerdotes de Dios y de Cristo, y reinarán con él mil años.  7 Y cuando los mil años fueren cumplidos, Satanás será suelto de su prisión,$x$),
($c$Apocalipsis 20:6$c$, $x$Bienaventurado y santo el que tiene parte en la primera resurrección: la segunda muerte no tiene potestad en éstos; antes serán sacerdotes de Dios y de Cristo, y reinarán con él mil años.$x$),
($c$Apocalipsis 20:7-9$c$, $x$7 Y cuando los mil años fueren cumplidos, Satanás será suelto de su prisión,  8 Y saldrá para engañar las naciones que están sobre los cuatro ángulos de la tierra, á Gog y á Magog, á fin de congregarlos para la batalla; el número de los cuales es como la arena del mar.  9 Y subieron sobre la anchura de la tierra, y circundaron el campo de los santos, y la ciudad amada: y de Dios descendió fuego del cielo, y los devoró.$x$),
($c$Apocalipsis 22:1$c$, $x$Después me mostró un río limpio de agua de vida, resplandeciente como cristal, que salía del trono de Dios y del Cordero.$x$),
($c$Apocalipsis 22:12$c$, $x$Y he aquí, yo vengo presto, y mi galardón conmigo, para recompensar á cada uno según fuere su obra.$x$),
($c$Apocalipsis 22:14$c$, $x$Bienaventurados los que guardan sus mandamientos, para que su potencia sea en el árbol de la vida, y que entren por las puertas en la ciudad.$x$),
($c$Apocalipsis 22:17$c$, $x$Y el Espíritu y la Esposa dicen: Ven. Y el que oye, diga: Ven. Y el que tiene sed, venga: y el que quiere, tome del agua de la vida de balde.$x$),
($c$Apocalipsis 3:14-17$c$, $x$14 Y escribe al ángel de la iglesia en LAODICEA: He aquí dice el Amén, el testigo fiel y verdadero, el principio de la creación de Dios:  15 Yo conozco tus obras, que ni eres frío, ni caliente. ¡Ojalá fueses frío, ó caliente!  16 Mas porque eres tibio, y no frío ni caliente, te vomitaré de mi boca.  17 Porque tú dices: Yo soy rico, y estoy enriquecido, y no tengo necesidad de ninguna cosa; y no conoces que tú eres un cuitado y miserable y pobre y ciego y desnudo;$x$),
($c$Apocalipsis 3:5$c$, $x$El que venciere, será vestido de vestiduras blancas; y no borraré su nombre del libro de la vida, y confesaré su nombre delante de mi Padre, y delante de sus ángeles.$x$),
($c$Apocalipsis 5:11$c$, $x$Y miré, y oí voz de muchos ángeles alrededor del trono, y de los animales, y de los ancianos; y la multitud de ellos era millones de millones,$x$),
($c$Apocalipsis 6:14-17$c$, $x$14 Y el cielo se apartó como un libro que es envuelto; y todo monte y las islas fueron movidas de sus lugares.  15 Y los reyes de la tierra, y los príncipes, y los ricos, y los capitanes, y los fuertes, y todo siervo y todo libre, se escondieron en las cuevas y entre las peñas de los montes;  16 Y decían á los montes y á las peñas: Caed sobre nosotros, y escondednos de la cara de aquél que está sentado sobre el trono, y de la ira del Cordero:  17 Porque el gran día de su ira es venido; ¿y quién podrá estar firme?$x$),
($c$Apocalipsis 7:9$c$, $x$Después de estas cosas miré, y he aquí una gran compañía, la cual ninguno podía contar, de todas gentes y linajes y pueblos y lenguas, que estaban delante del trono y en la presencia del Cordero, vestidos de ropas blancas, y palmas en sus manos;$x$),
($c$Colosenses 1:13-17$c$, $x$13 Que nos ha librado de la potestad de las tinieblas, y trasladado al reino de su amado Hijo;  14 En el cual tenemos redención por su sangre, la remisión de pecados:  15 El cual es la imagen del Dios invisible, el primogénito de toda criatura.  16 Porque por él fueron criadas todas las cosas que están en los cielos, y que están en la tierra, visibles é invisibles; sean tronos, sean dominios, sean principados, sean potestades; todo fué criado por él y para él.  17 Y él es antes de todas las cosas, y por él todas las cosas subsisten:$x$),
($c$Colosenses 1:18$c$, $x$Y él es la cabeza del cuerpo que es la iglesia; él que es el principio, el primogénito de los muertos, para que en todo tenga el primado.$x$),
($c$Colosenses 2:16, 17$c$, $x$16 Por tanto, nadie os juzgue en comida, ó en bebida, ó en parte de día de fiesta, ó de nueva luna, ó de sábados:  17 Lo cual es la sombra de lo por venir; mas el cuerpo es de Cristo.$x$),
($c$Daniel 12:10$c$, $x$Muchos serán limpios, y emblanquecidos, y purificados; mas los impíos obrarán impíamente, y ninguno de los impíos entenderá, pero entenderán los entendidos.$x$),
($c$Daniel 12:2$c$, $x$Y muchos de los que duermen en el polvo de la tierra serán despertados, unos para vida eterna, y otros para vergüenza y confusión perpetua.$x$),
($c$Daniel 12:4$c$, $x$Tú empero Daniel, cierra las palabras y sella el libro hasta el tiempo del fin: pasarán muchos, y multiplicaráse la ciencia.$x$),
($c$Daniel 12:9$c$, $x$Y dijo: Anda, Daniel, que estas palabras están cerradas y selladas hasta el tiempo del cumplimiento.$x$),
($c$Daniel 2:44$c$, $x$Y en los días de estos reyes, levantará el Dios del cielo un reino que nunca jamás se corromperá: y no será dejado á otro pueblo este reino; el cual desmenuzará y consumirá todos estos reinos, y él permanecerá para siempre.$x$),
($c$Daniel 7:10$c$, $x$Un río de fuego procedía y salía de delante de él: millares de millares le servían, y millones de millones asistían delante de él: el Juez se sentó, y los libros se abrieron.$x$),
($c$Daniel 7:13$c$, $x$Miraba yo en la visión de la noche, y he aquí en las nubes del cielo como un hijo de hombre que venía, y llegó hasta el Anciano de grande edad, é hiciéronle llegar delante de él.$x$),
($c$Daniel 7:14$c$, $x$Y fuéle dado señorío, y gloria, y reino; y todos los pueblos, naciones y lenguas le sirvieron; su señorío, señorío eterno, que no será transitorio, y su reino que no se corromperá.$x$),
($c$Daniel 7:17$c$, $x$Estas grandes bestias, las cuales son cuatro, cuatro reyes son, que se levantarán en la tierra.$x$),
($c$Daniel 7:19, 20$c$, $x$19 Entonces tuve deseo de saber la verdad acerca de la cuarta bestia, que tan diferente era de todas las otras, espantosa en gran manera, que tenía dientes de hierro, y sus uñas de metal, que devoraba y desmenuzaba, y las sobras hollaba con sus pies:  20 Asimismo acerca de los diez cuernos que tenía en su cabeza, y del otro que había subido, de delante del cual habían caído tres: y este mismo cuerno tenía ojos, y boca que hablaba grandezas, y su parecer mayor que el de sus compañeros.$x$),
($c$Daniel 7:2$c$, $x$Habló Daniel y dijo: Veía yo en mi visión de noche, y he aquí que los cuatro vientos del cielo combatían en la gran mar.$x$),
($c$Daniel 7:23$c$, $x$Dijo así: La cuarta bestia será un cuarto reino en la tierra, el cual será más grande que todos los otros reinos, y á toda la tierra devorará, y la hollará, y la despedazará.$x$),
($c$Daniel 7:24$c$, $x$Y los diez cuernos significan que de aquel reino se levantarán diez reyes; y tras ellos se levantará otro, el cual será mayor que los primeros, y á tres reyes derribará.$x$),
($c$Daniel 7:24 última p$c$, $x$Y los diez cuernos significan que de aquel reino se levantarán diez reyes; y tras ellos se levantará otro, el cual será mayor que los primeros, y á tres reyes derribará.$x$),
($c$Daniel 7:3$c$, $x$Y cuatro bestias grandes, diferentes la una de la otra, subían de la mar.$x$),
($c$Daniel 7:4$c$, $x$La primera era como león, y tenía alas de águila. Yo estaba mirando hasta tanto que sus alas fueron arrancadas, y fué quitada de la tierra; y púsose enhiesta sobre los pies á manera de hombre, y fuéle dado corazón de hombre.$x$),
($c$Daniel 7:5$c$, $x$Y he aquí otra segunda bestia, semejante á un oso, la cual se puso al un lado, y tenía en su boca tres costillas entre sus dientes; y fuéle dicho así: Levántate, traga carne mucha.$x$),
($c$Daniel 7:6$c$, $x$Después de esto yo miraba, y he aquí otra, semejante á un tigre, y tenía cuatro alas de ave en sus espaldas: tenía también esta bestia cuatro cabezas; y fuéle dada potestad.$x$),
($c$Daniel 7:7$c$, $x$Después de esto miraba yo en las visiones de la noche, y he aquí la cuarta bestia, espantosa y terrible, y en grande manera fuerte; la cual tenía unos dientes grandes de hierro: devoraba y desmenuzaba, y las sobras hollaba con sus pies: y era muy diferente de todas las bestias que habían sido antes de ella, y tenía diez cuernos.$x$)
insert into citas_texto (cita, texto) values
($c$Daniel 7:8$c$, $x$Estando yo contemplando los cuernos, he aquí que otro cuerno pequeño subía entre ellos, y delante de él fueron arrancados tres cuernos de los primeros; y he aquí, en este cuerno había ojos como ojos de hombre, y una boca que hablaba grandezas.$x$),
($c$Daniel 7:9$c$, $x$Estuve mirando hasta que fueron puestas sillas: y un Anciano de grande edad se sentó, cuyo vestido era blanco como la nieve, y el pelo de su cabeza como lana limpia; su silla llama de fuego, sus ruedas fuego ardiente.$x$),
($c$Daniel 7:9, 10$c$, $x$9 Estuve mirando hasta que fueron puestas sillas: y un Anciano de grande edad se sentó, cuyo vestido era blanco como la nieve, y el pelo de su cabeza como lana limpia; su silla llama de fuego, sus ruedas fuego ardiente.  10 Un río de fuego procedía y salía de delante de él: millares de millares le servían, y millones de millones asistían delante de él: el Juez se sentó, y los libros se abrieron.$x$),
($c$Daniel 9:27$c$, $x$Y en otra semana confirmará el pacto á muchos, y á la mitad de la semana hará cesar el sacrificio y la ofrenda: después con la muchedumbre de las abominaciones será el desolar, y esto hasta una entera consumación; y derramaráse la ya determinada sobre el pueblo asolado.$x$),
($c$Deuteronomio 10:4, 5$c$, $x$4 Y escribió en las tablas conforme á la primera escritura, las diez palabras que Jehová os había hablado en el monte de en medio del fuego, el día de la asamblea; y diómelas Jehová.  5 Y volví y descendí del monte, y puse las tablas en el arca que había hecho; y allí están, como Jehová me mandó.$x$),
($c$Deuteronomio 14:22$c$, $x$Indispensablemente diezmarás todo el producto de tu simiente, que rindiere el campo cada un año.$x$),
($c$Deuteronomio 29:29$c$, $x$Las cosas secretas pertenecen á Jehová nuestro Dios: mas las reveladas son para nosotros y para nuestros hijos por siempre, para que cumplamos todas las palabras de esta ley.$x$),
($c$Deuteronomio 31:25, 26$c$, $x$25 Mandó Moisés á los Levitas que llevaban el arca del pacto de Jehová, diciendo:  26 Tomad este libro de la ley, y ponedlo al lado del arca del pacto de Jehová vuestro Dios, y esté allí por testigo contra ti.$x$),
($c$Deuteronomio 4:12, 13$c$, $x$12 Y habló Jehová con vosotros de en medio del fuego: oisteis la voz de sus palabras, mas á excepción de oir la voz, ninguna figura visteis:  13 Y él os anunció su pacto, el cual os mandó poner por obra, las diez palabras; y escribiólas en dos tablas de piedra.$x$),
($c$Deuteronomio 4:13$c$, $x$Y él os anunció su pacto, el cual os mandó poner por obra, las diez palabras; y escribiólas en dos tablas de piedra.$x$),
($c$Deuteronomio 5:22$c$, $x$Estas palabras habló Jehová á toda vuestra congregación en el monte, de en medio del fuego, de la nube y de la oscuridad, á gran voz: y no añadió más. Y escribiólas en dos tablas de piedra, las cuales me dió á mí.$x$),
($c$Eclesiastés 12:13$c$, $x$El fin de todo el discurso oído es este: Teme á Dios, y guarda sus mandamientos; porque esto es el todo del hombre.$x$),
($c$Eclesiastés 12:13, 14$c$, $x$13 El fin de todo el discurso oído es este: Teme á Dios, y guarda sus mandamientos; porque esto es el todo del hombre.  14 Porque Dios traerá toda obra á juicio, el cual se hará sobre toda cosa oculta, buena ó mala.$x$),
($c$Eclesiastés 12:7$c$, $x$Y el polvo se torne á la tierra, como era, y el espíritu se vuelva á Dios que lo dió.$x$),
($c$Eclesiastés 3:19$c$, $x$Porque el suceso de los hijos de los hombres, y el suceso del animal, el mismo suceso es: como mueren los unos, así mueren los otros; y una misma respiración tienen todos; ni tiene más el hombre que la bestia: porque todo es vanidad.$x$),
($c$Eclesiastés 3:20$c$, $x$Todo va á un lugar: todo es hecho del polvo, y todo se tornará en el mismo polvo.$x$),
($c$Eclesiastés 9:10$c$, $x$Todo lo que te viniere á la mano para hacer, hazlo según tus fuerzas; porque en el sepulcro, adonde tú vas, no hay obra, ni industria, ni ciencia, ni sabiduría.$x$),
($c$Eclesiastés 9:5$c$, $x$Porque los que viven saben que han de morir: mas los muertos nada saben, ni tienen más paga; porque su memoria es puesta en olvido.$x$),
($c$Eclesiastés 9:6$c$, $x$También su amor, y su odio y su envidia, feneció ya: ni tiene ya más parte en el siglo, en todo lo que se hace debajo del sol.$x$),
($c$Efesios 1:22, 23$c$, $x$22 Y sometió todas las cosas debajo de sus pies, y diólo por cabeza sobre todas las cosas á la iglesia,  23 La cual es su cuerpo, la plenitud de Aquel que hinche todas las cosas en todos.$x$),
($c$Efesios 2:15$c$, $x$Dirimiendo en su carne las enemistades, la ley de los mandamientos en orden á ritos, para edificar en sí mismo los dos en un nuevo hombre, haciendo la paz,$x$),
($c$Efesios 2:15, 16$c$, $x$15 Dirimiendo en su carne las enemistades, la ley de los mandamientos en orden á ritos, para edificar en sí mismo los dos en un nuevo hombre, haciendo la paz,  16 Y reconciliar por la cruz con Dios á ambos en un mismo cuerpo, matando en ella las enemistades.$x$),
($c$Efesios 2:20$c$, $x$Edificados sobre el fundamento de los apóstoles y profetas, siendo la principal piedra del ángulo Jesucristo mismo;$x$),
($c$Efesios 3:9$c$, $x$Y de aclarar á todos cuál sea la dispensación del misterio escondido desde los siglos en Dios, que crió todas las cosas.$x$),
($c$Efesios 5:26, 27$c$, $x$26 Para santificarla limpiándola en el lavacro del agua por la palabra,  27 Para presentársela gloriosa para sí, una iglesia que no tuviese mancha ni arruga, ni cosa semejante; sino que fuese santa y sin mancha.$x$),
($c$Exodo 20:10$c$, $x$Mas el séptimo día será reposo para Jehová tu Dios: no hagas en él obra alguna, tú, ni tu hijo, ni tu hija, ni tu siervo, ni tu criada ni tu bestia, ni tu extranjero que está dentro de tus puertas:$x$),
($c$Ezequiel 18:4$c$, $x$He aquí que todas las almas son mías; como el alma del padre, así el alma del hijo es mía; el alma que pecare, esa morirá.$x$),
($c$Ezequiel 28:15$c$, $x$Perfecto eras en todos tus caminos desde el día que fuiste criado, hasta que se halló en ti maldad.$x$),
($c$Ezequiel 28:17$c$, $x$Enaltecióse tu corazón á causa de tu hermosura, corrompiste tu sabiduría á causa de tu resplandor: yo te arrojaré por tierra; delante de los reyes te pondré para que miren en ti.$x$),
($c$Ezequiel 28:18, 19$c$, $x$18 Con la multitud de tus maldades, y con la iniquidad de tu contratación ensuciaste tu santuario: yo pues saqué fuego de en medio de ti, el cual te consumió, y púsete en ceniza sobre la tierra á los ojos de todos los que te miran.  19 Todos los que te conocieron de entre los pueblos, se maravillarán sobre ti: en espanto serás, y para siempre dejarás de ser.$x$),
($c$Ezequiel 33:31$c$, $x$Y vendrán á ti como viene el pueblo, y se estarán delante de ti como mi pueblo, y oirán tus palabras, y no las pondrán por obra: antes hacen halagos con sus bocas, y el corazón de ellos anda en pos de su avaricia.$x$),
($c$Filipenses 3:17$c$, $x$Hermanos, sed imitadores de mí, y mirad los que así anduvieren como nos tenéis por ejemplo.$x$),
($c$Filipenses 3:20,21$c$, $x$20 Mas nuestra vivienda es en los cielos; de donde también esperamos al Salvador, al Señor Jesucristo;  21 El cual transformará el cuerpo de nuestra bajeza, para ser semejante al cuerpo de su gloria, por la operación con la cual puede también sujetar á sí todas las cosas.$x$),
($c$Gálatas 3:16, 29$c$, $x$16 A Abraham fueron hechas las promesas, y á su simiente. No dice: Y á las simientes, como de muchos; sino como de uno: Y á tu simiente, la cual es Cristo.  29 Y si vosotros sois de Cristo, ciertamente la simiente de Abraham sois, y conforme á la promesa los herederos.$x$),
($c$Gálatas 4:26$c$, $x$Mas la Jerusalem de arriba libre es; la cual es la madre de todos nosotros.$x$),
($c$Gálatas 6:6$c$, $x$Y el que es enseñado en la palabra, comunique en todos los bienes al que lo instruye.$x$),
($c$Gálatas 6:8$c$, $x$Porque el que siembra para su carne, de la carne segará corrupción; mas el que siembra para el Espíritu, del Espíritu segará vida eterna.$x$),
($c$Gén. 5:24$c$, $x$Caminó, pues, Henoch con Dios, y desapareció, porque le llevó Dios.$x$),
($c$Génesis 1:26-28$c$, $x$26 Y dijo Dios: Hagamos al hombre á nuestra imagen, conforme á nuestra semejanza; y señoree en los peces de la mar, y en las aves de los cielos, y en las bestias, y en toda la tierra, y en todo animal que anda arrastrando sobre la tierra.  27 Y crió Dios al hombre á su imagen, á imagen de Dios lo crió; varón y hembra los crió.  28 Y los bendijo Dios; y díjoles Dios: Fructificad y multiplicad, y henchid la tierra, y sojuzgadla, y señoread en los peces de la mar, y en las aves de los cielos, y en todas las bestias que se mueven sobre la tierra.$x$),
($c$Génesis 2:17$c$, $x$Mas del árbol de ciencia del bien y del mal no comerás de él; porque el día que de él comieres, morirás.$x$),
($c$Génesis 2:2$c$, $x$Y acabó Dios en el día séptimo su obra que hizo, y reposó el día séptimo de toda su obra que había hecho.$x$),
($c$Génesis 2:3$c$, $x$Y bendijo Dios al día séptimo, y santificólo, porque en él reposó de toda su obra que había Dios criado y hecho.$x$),
($c$Génesis 2:7$c$, $x$Formó, pues, Jehová Dios al hombre del polvo de la tierra, y alentó en su nariz soplo de vida; y fué el hombre en alma viviente.$x$),
($c$Génesis 2:7 primera parte$c$, $x$Formó, pues, Jehová Dios al hombre del polvo de la tierra, y alentó en su nariz soplo de vida; y fué el hombre en alma viviente.$x$),
($c$Génesis 2:7 última parte$c$, $x$Formó, pues, Jehová Dios al hombre del polvo de la tierra, y alentó en su nariz soplo de vida; y fué el hombre en alma viviente.$x$),
($c$Génesis 3:1-6$c$, $x$1 Empero la serpiente era astuta, más que todos los animales del campo que Jehová Dios había hecho; la cual dijo á la mujer: ¿Conque Dios os ha dicho: No comáis de todo árbol del huerto?  2 Y la mujer respondió á la serpiente: Del fruto de los árboles del huerto comemos;  3 Mas del fruto del árbol que está en medio del huerto dijo Dios: No comeréis de él, ni le tocaréis, porque no muráis.  4 Entonces la serpiente dijo á la mujer: No moriréis;  5 Mas sabe Dios que el día que comiereis de él, serán abiertos vuestros ojos, y seréis como dioses sabiendo el bien y el mal.  6 Y vió la mujer que el árbol era bueno para comer, y que era agradable á los ojos, y árbol codiciable para alcanzar la sabiduría; y tomó de su fruto, y comió; y dió también á su marido, el cual comió así como ella.$x$),
($c$Génesis 3:19$c$, $x$En el sudor de tu rostro comerás el pan hasta que vuelvas á la tierra; porque de ella fuiste tomado: pues polvo eres, y al polvo serás tornado.$x$),
($c$Génesis 3:6$c$, $x$Y vió la mujer que el árbol era bueno para comer, y que era agradable á los ojos, y árbol codiciable para alcanzar la sabiduría; y tomó de su fruto, y comió; y dió también á su marido, el cual comió así como ella.$x$),
($c$Génesis 5:5, 8, 11, 14, 17, 20, 27, 31$c$, $x$5 Y fueron todos los días que vivió Adam novecientos y treinta años, y murió.  8 Y fueron todos los días de Seth novecientos y doce años; y murió.  11 Y fueron todos los días de Enós novecientos y cinco años; y murió.  14 Y fueron todos los días de Cainán novecientos y diez años; y murió.  17 Y fueron todos los días de Mahalaleel ochocientos noventa y cinco años; y murió.  20 Y fueron todos los días de Jared novecientos sesenta y dos años; y murió.  27 Fueron, pues, todos los días de Mathusalam, novecientos sesenta y nueve años; y murió.  31 Y fueron todos los días de Lamech setecientos setenta y siete años; y murió.$x$),
($c$Génesis 7:21, 22$c$, $x$21 Y murió toda carne que se mueve sobre la tierra, así de aves como de ganados, y de bestias, y de todo reptil que anda arrastrando sobre la tierra, y todo hombre:  22 Todo lo que tenía aliento de espíritu de vida en sus narices, de todo lo que había en la tierra, murió.$x$),
($c$Heb. 4:14, 15$c$, $x$14 Por tanto, teniendo un gran Pontífice, que penetró los cielos, Jesús el Hijo de Dios, retengamos nuestra profesión.  15 Porque no tenemos un Pontífice que no se pueda compadecer de nuestras flaquezas; mas tentado en todo según nuestra semejanza, pero sin pecado.$x$),
($c$Hebreos 10:1$c$, $x$Porque la ley, teniendo la sombra de los bienes venideros, no la imagen misma de las cosas, nunca puede, por los mismos sacrificios que ofrecen continuamente cada año, hacer perfectos á los que se allegan.$x$),
($c$Hebreos 10:1-10$c$, $x$1 Porque la ley, teniendo la sombra de los bienes venideros, no la imagen misma de las cosas, nunca puede, por los mismos sacrificios que ofrecen continuamente cada año, hacer perfectos á los que se allegan.  2 De otra manera cesarían de ofrecerse; porque los que tributan este culto, limpios de una vez, no tendrían más conciencia de pecado.  3 Empero en estos sacrificios cada año se hace conmemoración de los pecados.  4 Porque la sangre de los toros y de los machos cabríos no puede quitar los pecados.  5 Por lo cual, entrando en el mundo, dice: Sacrificio y presente no quisiste; mas me apropiaste cuerpo:  6 Holocaustos y expiaciones por el pecado no te agradaron.  7 Entonces dije: Heme aquí (en la cabecera del libro está escrito de mí) para que haga, oh Dios, tu voluntad.  8 Diciendo arriba: Sacrificio y presente, y holocaustos y expiaciones por el pecado no quisiste, ni te agradaron, (las cuales cosas se ofrecen según la ley,)  9 Entonces dijo: Heme aquí para que haga, oh Dios, tu voluntad. Quita lo primero, para establecer lo postrero.  10 En la cual voluntad somos santificados por la ofrenda del cuerpo de Jesucristo hecha una sola vez.$x$),
($c$Hebreos 10:7$c$, $x$Entonces dije: Heme aquí (en la cabecera del libro está escrito de mí) para que haga, oh Dios, tu voluntad.$x$),
($c$Hebreos 11:14-16$c$, $x$14 Porque los que esto dicen, claramente dan á entender que buscan una patria.  15 Que si se acordaran de aquella de donde salieron, cierto tenían tiempo para volverse:  16 Empero deseaban la mejor, es á saber, la celestial; por lo cual Dios no se avergüenza de llamarse Dios de ellos: porque les había aparejado ciudad.$x$),
($c$Hebreos 11:4$c$, $x$Por la fe Abel ofreció á Dios mayor sacrificio que Caín, por la cual alcanzó testimonio de que era justo, dando Dios testimonio á sus presentes; y difunto, aun habla por ella.$x$),
($c$Hebreos 11:5$c$, $x$Por la fe Enoc fué traspuesto para no ver muerte, y no fué hallado, porque lo traspuso Dios. Y antes que fuese traspuesto, tuvo testimonio de haber agradado á Dios.$x$),
($c$Hebreos 11:6$c$, $x$Empero sin fe es imposible agradar á Dios; porque es menester que el que á Dios se allega, crea que le hay, y que es galardonador de los que le buscan.$x$),
($c$Hebreos 11:8-16$c$, $x$8 Por la fe Abraham, siendo llamado, obedeció para salir al lugar que había de recibir por heredad; y salió sin saber dónde iba.  9 Por fe habitó en la tierra prometida como en tierra ajena, morando en cabañas con Isaac y Jacob, herederos juntamente de la misma promesa:  10 Porque esperaba ciudad con fundamentos, el artífice y hacedor de la cual es Dios.  11 Por la fe también la misma Sara, siendo estéril, recibió fuerza para concebir simiente; y parió aun fuera del tiempo de la edad, porque creyó ser fiel el que lo había prometido.  12 Por lo cual también, de uno, y ése ya amortecido, salieron como las estrellas del cielo en multitud, y como la arena innumerable que está á la orilla de la mar.  13 Conforme á la fe murieron todos éstos sin haber recibido las promesas, sino mirándolas de lejos, y creyéndolas, y saludándolas, y confesando que eran peregrinos y advenedizos sobre la tierra.  14 Porque los que esto dicen, claramente dan á entender que buscan una patria.  15 Que si se acordaran de aquella de donde salieron, cierto tenían tiempo para volverse:  16 Empero deseaban la mejor, es á saber, la celestial; por lo cual Dios no se avergüenza de llamarse Dios de ellos: porque les había aparejado ciudad.$x$),
($c$Hebreos 12:22$c$, $x$Mas os habéis llegado al monte de Sión, y á la ciudad del Dios vivo, Jerusalem la celestial, y á la compañía de muchos millares de ángeles,$x$),
($c$Hebreos 13:14$c$, $x$Porque no tenemos aquí ciudad permanente, mas buscamos la por venir.$x$),
($c$Hebreos 13:7, 16$c$, $x$7 Acordaos de vuestros pastores, que os hablaron la palabra de Dios; la fe de los cuales imitad, considerando cuál haya sido el éxito de su conducta.  16 Y de hacer bien y de la comunicación no os olvidéis: porque de tales sacrificios se agrada Dios.$x$)
insert into citas_texto (cita, texto) values
($c$Hebreos 13:8$c$, $x$Jesucristo es el mismo ayer, y hoy, y por los siglos.$x$),
($c$Hebreos 1:1, 2$c$, $x$1 Dios, habiendo hablado muchas veces y en muchas maneras en otro tiempo á los padres por los profetas,  2 En estos postreros días nos ha hablado por el Hijo, al cual constituyó heredero de todo, por el cual asimismo hizo el universo:$x$),
($c$Hebreos 1:1-3$c$, $x$1 Dios, habiendo hablado muchas veces y en muchas maneras en otro tiempo á los padres por los profetas,  2 En estos postreros días nos ha hablado por el Hijo, al cual constituyó heredero de todo, por el cual asimismo hizo el universo:  3 El cual siendo el resplandor de su gloria, y la misma imagen de su sustancia, y sustentando todas las cosas con la palabra de su potencia, habiendo hecho la purgación de nuestros pecados por sí mismo, se sentó á la diestra de la Majestad en las alturas,$x$),
($c$Hebreos 2:14$c$, $x$Así que, por cuanto los hijos participaron de carne y sangre, él también participó de lo mismo, para destruir por la muerte al que tenía el imperio de la muerte, es á saber, al diablo,$x$),
($c$Hebreos 3:1$c$, $x$Por tanto, hermanos santos, participantes de la vocación celestial, considerad al Apóstol y Pontífice de nuestra profesión, Cristo Jesús;$x$),
($c$Hebreos 4:15$c$, $x$Porque no tenemos un Pontífice que no se pueda compadecer de nuestras flaquezas; mas tentado en todo según nuestra semejanza, pero sin pecado.$x$),
($c$Hebreos 8:1,2$c$, $x$1 Así que, la suma acerca de lo dicho es: Tenemos tal pontífice que se asentó á la diestra del trono de la Majestad en los cielos;  2 Ministro del santuario, y de aquel verdadero tabernáculo que el Señor asentó, y no hombre.$x$),
($c$Hebreos 8:5$c$, $x$Los cuales sirven de bosquejo y sombra de las cosas celestiales, como fué respondido á Moisés cuando había de acabar el tabernáculo: Mira, dice, haz todas las cosas conforme al dechado que te ha sido mostrado en el monte.$x$),
($c$Hebreos 9:1$c$, $x$Tenía empero también el primer pacto reglamentos del culto, y santuario mundano.$x$),
($c$Hebreos 9:10$c$, $x$Consistiendo sólo en viandas y en bebidas, y en diversos lavamientos, y ordenanzas acerca de la carne, impuestas hasta el tiempo de la corrección.$x$),
($c$Hebreos 9:2$c$, $x$Porque el tabernáculo fué hecho: el primero, en que estaban las lámparas, y la mesa, y los panes de la proposición; lo que llaman el Santuario.$x$),
($c$Hebreos 9:24$c$, $x$Porque no entró Cristo en el santuario hecho de mano, figura del verdadero, sino en el mismo cielo para presentarse ahora por nosotros en la presencia de Dios.$x$),
($c$Hebreos 9:27$c$, $x$Y de la manera que está establecido á los hombres que mueran una vez, y después el juicio;$x$),
($c$Hebreos 9:3,4$c$, $x$3 Tras el segundo velo estaba el tabernáculo, que llaman el Lugar Santísimo;  4 El cual tenía un incensario de oro, y el arca del pacto cubierta de todas partes alrededor de oro; en la que estaba una urna de oro que contenía el maná, y la vara de Aarón que reverdeció, y las tablas del pacto;$x$),
($c$Hebreos 9:9$c$, $x$Lo cual era figura de aquel tiempo presente, en el cual se ofrecían presentes y sacrificios que no podían hacer perfecto, cuanto á la conciencia, al que servía con ellos;$x$),
($c$Hech. 1:11$c$, $x$Los cuales también les dijeron: Varones Galileos, ¿qué estáis mirando al cielo? este mismo Jesús que ha sido tomado desde vosotros arriba en el cielo, así vendrá como le habéis visto ir al cielo.$x$),
($c$Hechos 13:14$c$, $x$Y ellos pasando de Perge, llegaron á Antioquía de Pisidia, y entrando en la sinagoga un día de sábado, sentáronse.$x$),
($c$Hechos 13:14, 42, 44$c$, $x$14 Y ellos pasando de Perge, llegaron á Antioquía de Pisidia, y entrando en la sinagoga un día de sábado, sentáronse.  42 Y saliendo ellos de la sinagoga de los Judíos, los Gentiles les rogaron que el sábado siguiente les hablasen estas palabras.  44 Y el sábado siguiente se juntó casi toda la ciudad á oir la palabra de Dios.$x$),
($c$Hechos 13:2$c$, $x$Ministrando pues éstos al Señor, y ayunando, dijo el Espíritu Santo: Apartadme á Bernabé y á Saulo para la obra para la cual los he llamado.$x$),
($c$Hechos 13:2, 4$c$, $x$2 Ministrando pues éstos al Señor, y ayunando, dijo el Espíritu Santo: Apartadme á Bernabé y á Saulo para la obra para la cual los he llamado.  4 Y ellos, enviados así por el Espíritu Santo, descendieron á Seleucia; y de allí navegaron á Cipro.$x$),
($c$Hechos 13:36$c$, $x$Porque á la verdad David, habiendo servido en su edad á la voluntad de Dios, durmió, y fué juntado con sus padres, y vió corrupción:$x$),
($c$Hechos 13:42$c$, $x$Y saliendo ellos de la sinagoga de los Judíos, los Gentiles les rogaron que el sábado siguiente les hablasen estas palabras.$x$),
($c$Hechos 15:28, 29$c$, $x$28 Que ha parecido bien al Espíritu Santo, y á nosotros, no imponeros ninguna carga más que estas cosas necesarias:  29 Que os abstengáis de cosas sacrificadas á ídolos, y de sangre, y de ahogado, y de fornicación; de las cuales cosas si os guardareis, bien haréis. Pasadlo bien.$x$),
($c$Hechos 16:13$c$, $x$Y un día de sábado salimos de la puerta junto al río, donde solía ser la oración; y sentándonos, hablamos á las mujeres que se habían juntado.$x$),
($c$Hechos 17:2$c$, $x$Y Pablo, como acostumbraba, entró á ellos, y por tres sábados disputó con ellos de las Escrituras,$x$),
($c$Hechos 18:1-3$c$, $x$1 Pasadas estas cosas, Pablo partió de Atenas, y vino á Corinto.  2 Y hallando á un Judío llamado Aquila, natural del Ponto, que hacía poco que había venido de Italia, y á Priscila su mujer, (porque Claudio había mandado que todos los Judíos saliesen de Roma) se vino á ellos;  3 Y porque era de su oficio, posó con ellos, y trabajaba; porque el oficio de ellos era hacer tiendas.$x$),
($c$Hechos 18:1-4, 11$c$, $x$1 Pasadas estas cosas, Pablo partió de Atenas, y vino á Corinto.  2 Y hallando á un Judío llamado Aquila, natural del Ponto, que hacía poco que había venido de Italia, y á Priscila su mujer, (porque Claudio había mandado que todos los Judíos saliesen de Roma) se vino á ellos;  3 Y porque era de su oficio, posó con ellos, y trabajaba; porque el oficio de ellos era hacer tiendas.  4 Y disputaba en la sinagoga todos los sábados, y persuadía á Judíos y á Griegos.  11 Y se detuvo allí un año y seis meses, enseñándoles la palabra de Dios.$x$),
($c$Hechos 18:11$c$, $x$Y se detuvo allí un año y seis meses, enseñándoles la palabra de Dios.$x$),
($c$Hechos 18:13$c$, $x$Diciendo: Que éste persuade á los hombres á honrar á Dios contra la ley.$x$),
($c$Hechos 18:4$c$, $x$Y disputaba en la sinagoga todos los sábados, y persuadía á Judíos y á Griegos.$x$),
($c$Hechos 1:14$c$, $x$Todos éstos perseveraban unánimes en oración y ruego, con las mujeres, y con María la madre de Jesús, y con sus hermanos.$x$),
($c$Hechos 1:9-11$c$, $x$9 Y habiendo dicho estas cosas, viéndolo ellos, fué alzado; y una nube le recibió y le quitó de sus ojos.  10 Y estando con los ojos puestos en el cielo, entre tanto que él iba, he aquí dos varones se pusieron junto á ellos en vestidos blancos;  11 Los cuales también les dijeron: Varones Galileos, ¿qué estáis mirando al cielo? este mismo Jesús que ha sido tomado desde vosotros arriba en el cielo, así vendrá como le habéis visto ir al cielo.$x$),
($c$Hechos 20:17, 25-28$c$, $x$17 Y enviando desde Mileto á Efeso, hizo llamar á los ancianos de la iglesia.  25 Y ahora, he aquí, yo sé que ninguno de todos vosotros, por quien he pasado predicando el reino de Dios, verá más mi rostro.  26 Por tanto, yo os protesto el día de hoy, que yo soy limpio de la sangre de todos:  27 Porque no he rehuído de anunciaros todo el consejo de Dios.  28 Por tanto mirad por vosotros, y por todo el rebaño en que el Espíritu Santo os ha puesto por obispos, para apacentar la iglesia del Señor, la cual ganó por su sangre.$x$),
($c$Hechos 20:31-35$c$, $x$31 Por tanto, velad, acordándoos que por tres años de noche y de día, no he cesado de amonestar con lágrimas á cada uno.  32 Y ahora, hermanos, os encomiendo á Dios, y á la palabra de su gracia: el cual es poderoso para sobreedificar, y daros heredad con todos los santificados.  33 La plata, ó el oro, ó el vestido de nadie he codiciado.  34 Antes vosotros sabéis que para lo que me ha sido necesario, y á los que están conmigo, estas manos me han servido.  35 En todo os he enseñado que, trabajando así, es necesario sobrellevar á los enfermos, y tener presente las palabras del Señor Jesús, el cual dijo: Más bienaventurada cosa es dar que recibir.$x$),
($c$Hechos 24:15$c$, $x$Teniendo esperanza en Dios que ha de haber resurrección de los muertos, así de justos como de injustos, la cual también ellos esperan.$x$),
($c$Hechos 24:25$c$, $x$Y disertando él de la justicia, y de la continencia, y del juicio venidero, espantado Félix, respondió: Ahora vete; mas en teniendo oportunidad te llamaré:$x$),
($c$Hechos 26:22-29$c$, $x$22 Mas ayudado del auxilio de Dios, persevero hasta el día de hoy, dando testimonio á pequeños y á grandes, no diciendo nada fuera de las cosas que los profetas y Moisés dijeron que habían de venir:  23 Que Cristo había de padecer, y ser el primero de la resurrección de los muertos, para anunciar luz al pueblo y á los Gentiles.  24 Y diciendo él estas cosas en su defensa, Festo á gran voz dijo: Estás loco, Pablo: las muchas letras te vuelven loco.  25 Mas él dijo: No estoy loco, excelentísimo Festo, sino que hablo palabras de verdad y de templanza.  26 Pues el rey sabe estas cosas, delante del cual también hablo confiadamente. Pues no pienso que ignora nada de esto; pues no ha sido esto hecho en algún rincón.  27 ¿Crees, rey Agripa, á los profetas? Yo sé que crees.  28 Entonces Agripa dijo á Pablo: Por poco me persuades á ser Cristiano.  29 Y Pablo dijo: ¡Pluguiese á Dios que por poco ó por mucho, no solamente tú, mas también todos los que hoy me oyen, fueseis hechos tales cual yo soy, excepto estas prisiones!$x$),
($c$Hechos 28:10$c$, $x$Los cuales también nos honraron con muchos obsequios; y cuando partimos, nos cargaron de las cosas necesarias.$x$),
($c$Hechos 2:34$c$, $x$Porque David no subió á los cielos; empero él dice: Dijo el Señor á mi Señor: Siéntate á mi diestra,$x$),
($c$Hechos 2:41, 47$c$, $x$41 Así que, los que recibieron su palabra, fueron bautizados: y fueron añadidas á ellos aquel día como tres mil personas.  47 Alabando á Dios, y teniendo gracia con todo el pueblo. Y el Señor añadía cada día á la iglesia los que habían de ser salvos.$x$),
($c$Hechos 3:21$c$, $x$Al cual de cierto es menester que el cielo tenga hasta los tiempos de la restauración de todas las cosas, que habló Dios por boca de sus santos profetas que han sido desde el siglo.$x$),
($c$Hechos 3:9$c$, $x$Y todo el pueblo le vió andar y alabar á Dios.$x$),
($c$Hechos 4:12$c$, $x$Y en ningún otro hay salud; porque no hay otro nombre debajo del cielo, dado á los hombres, en que podamos ser salvos.$x$),
($c$Hechos 4:13$c$, $x$Entonces viendo la constancia de Pedro y de Juan, sabido que eran hombres sin letras é ignorantes, se maravillaban; y les conocían que habían estado con Jesús.$x$),
($c$Hechos 6:13, 14$c$, $x$13 Y pusieron testigos falsos, que dijesen: Este hombre no cesa de hablar palabras blasfemas contra este lugar santo y la ley:  14 Porque le hemos oído decir, que este Jesús de Nazaret destruirá este lugar, y mudará las ordenanzas que nos dió Moisés.$x$),
($c$Hechos 6:3$c$, $x$Buscad pues, hermanos, siete varones de vosotros de buen testimonio, llenos de Espíritu Santo y de sabiduría, los cuales pongamos en esta obra.$x$),
($c$Hechos 7:55, 60$c$, $x$55 Mas él, estando lleno de Espíritu Santo, puestos los ojos en el cielo, vió la gloria de Dios, y á Jesús que estaba á la diestra de Dios,  60 Y puesto de rodillas, clamó á gran voz: Señor, no les imputes este pecado. Y habiendo dicho esto, durmió.$x$),
($c$Isaías 14:12$c$, $x$¡Cómo caiste del cielo, oh Lucero, hijo de la mañana! Cortado fuiste por tierra, tú que debilitabas las gentes.$x$),
($c$Isaías 14:13, 14$c$, $x$13 Tú que decías en tu corazón: Subiré al cielo, en lo alto junto á las estrellas de Dios ensalzaré mi solio, y en el monte del testimonio me sentaré, á los lados del aquilón;  14 Sobre las alturas de las nubes subiré, y seré semejante al Altísimo.$x$),
($c$Isaías 25:8$c$, $x$Destruirá á la muerte para siempre; y enjugará el Señor toda lágrima de todos los rostros: y quitará la afrenta de su pueblo de toda la tierra: porque Jehová lo ha dicho.$x$),
($c$Isaías 25:9$c$, $x$Y se dirá en aquel día: He aquí éste es nuestro Dios, le hemos esperado, y nos salvará: éste es Jehová á quien hemos esperado, nos gozaremos y nos alegraremos en su salud.$x$),
($c$Isaías 3:14, 15$c$, $x$14 Jehová vendrá á juicio contra los ancianos de su pueblo y contra sus príncipes; porque vosotros habéis devorado la viña, y el despojo del pobre está en vuestras casas.  15 ¿Qué pensáis vosotros que majáis mi pueblo, y moléis las caras de los pobres? dice el Señor Jehová de los ejércitos.$x$),
($c$Isaías 45:18$c$, $x$Porque así dijo Jehová, que crió los cielos; él es Dios, el que formó la tierra, el que la hizo y la compuso; no la crió en vano, para que fuese habitada la crió: Yo Jehová, y ninguno más que yo.$x$),
($c$Isaías 55:1$c$, $x$A todos los sedientos: Venid á las aguas; y los que no tienen dinero, venid, comprad, y comed. Venid, comprad, sin dinero y sin precio, vino y leche.$x$),
($c$Isaías 58:12, 13$c$, $x$12 Y edificarán los de ti los desiertos antiguos; los cimientos de generación y generación levantarás: y serás llamado reparador de portillos, restaurador de calzadas para habitar.  13 Si retrajeres del sábado tu pie, de hacer tu voluntad en mi día santo, y al sábado llamares delicias, santo, glorioso de Jehová; y lo venerares, no haciendo tus caminos, ni buscando tu voluntad, ni hablando tus palabras:$x$),
($c$Isaías 58:13$c$, $x$Si retrajeres del sábado tu pie, de hacer tu voluntad en mi día santo, y al sábado llamares delicias, santo, glorioso de Jehová; y lo venerares, no haciendo tus caminos, ni buscando tu voluntad, ni hablando tus palabras:$x$),
($c$Isaías 65:17$c$, $x$Porque he aquí que yo crío nuevos cielos y nueva tierra: y de lo primero no habrá memoria, ni más vendrá al pensamiento.$x$),
($c$Isaías 66:22$c$, $x$Porque como los cielos nuevos y la nueva tierra, que yo hago, permanecen delante de mí, dice Jehová, así permanecerá vuestra simiente y vuestro nombre.$x$),
($c$Isaías 66:22, 23$c$, $x$22 Porque como los cielos nuevos y la nueva tierra, que yo hago, permanecen delante de mí, dice Jehová, así permanecerá vuestra simiente y vuestro nombre.  23 Y será que de mes en mes, y de sábado en sábado, vendrá toda carne á adorar delante de mí, dijo Jehová.$x$),
($c$Isaías 66:23$c$, $x$Y será que de mes en mes, y de sábado en sábado, vendrá toda carne á adorar delante de mí, dijo Jehová.$x$),
($c$Isaías 7:14$c$, $x$Por tanto el mismo Señor os dará señal: He aquí que la virgen concebirá, y parirá hijo, y llamará su nombre Emmanuel.$x$),
($c$Isaías 8:20$c$, $x$¡A la ley y al testimonio! Si no dijeren conforme á esto, es porque no les ha amanecido.$x$)
insert into citas_texto (cita, texto) values
($c$Jeremías 13:18$c$, $x$Di al rey y á la reina: Humillaos, sentaos en tierra; porque la corona de vuestra gloria bajó de vuestras cabezas.$x$),
($c$Jeremías 25:31-33$c$, $x$31 Llegó el estruendo hasta el cabo de la tierra; porque juicio de Jehová con las gentes: él es el Juez de toda carne; entregará los impíos á cuchillo, dice Jehová.  32 Así ha dicho Jehová de los ejércitos: He aquí que el mal sale de gente en gente, y grande tempestad se levantará de los fines de la tierra.  33 Y serán muertos de Jehová en aquel día desde el un cabo de la tierra hasta el otro cabo; no se endecharán, ni se recogerán, ni serán enterrados; como estiércol serán sobre la haz de la tierra.$x$),
($c$Jeremías 49:36 ,37$c$, $x$36 Y traeré sobre Elam los cuatro vientos de los cuatro puntos del cielo, y aventarélos á todos estos vientos; ni habrá gente adonde no vengan extranjeros de Elam.  37 Y haré que Elam se intimide delante de sus enemigos, y delante de los que buscan su alma; y traeré sobre ellos mal, y el furor de mi enojo, dice Jehová; y enviaré en pos de ellos espada hasta que los acabe.$x$),
($c$Job 14:10-12$c$, $x$10 Mas el hombre morirá, y será cortado; y perecerá el hombre, ¿y dónde estará él?  11 Las aguas de la mar se fueron, y agotóse el río, secóse.  12 Así el hombre yace, y no se tornará á levantar: hasta que no haya cielo no despertarán, ni se levantarán de su sueño.$x$),
($c$Job 14:12$c$, $x$Así el hombre yace, y no se tornará á levantar: hasta que no haya cielo no despertarán, ni se levantarán de su sueño.$x$),
($c$Job 14:14$c$, $x$Si el hombre muriere, ¿volverá á vivir? Todos los días de mi edad esperaré, hasta que venga mi mutación.$x$),
($c$Job 14:21$c$, $x$Sus hijos serán honrados, y él no lo sabrá; ó serán humillados, y no entenderá de ellos.$x$),
($c$Job 17:13$c$, $x$Si yo espero, el sepulcro es mi casa: haré mi cama en las tinieblas.$x$),
($c$Job 19:23-27$c$, $x$23 ¡Quién diese ahora que mis palabras fuesen escritas! ¡quién diese que se escribieran en un libro!  24 ¡Que con cincel de hierro y con plomo fuesen en piedra esculpidas para siempre!  25 Yo sé que mi Redentor vive, y al fin se levantará sobre el polvo:  26 Y después de deshecha esta mi piel, aun he de ver en mi carne á Dios;  27 Al cual yo tengo de ver por mí, y mis ojos lo verán, y no otro, aunque mis riñones se consuman dentro de mí.$x$),
($c$Job 27:3$c$, $x$Que todo el tiempo que mi alma estuviere en mí, y hubiere hálito de Dios en mis narices,$x$),
($c$Job 38:22, 23$c$, $x$22 ¿Has tú entrado en los tesoros de la nieve, ó has visto los tesoros del granizo,  23 Lo cual tengo yo reservado para el tiempo de angustia, para el día de la guerra y de la batalla?$x$),
($c$Joel 1:15 -20$c$, $x$15 ¡Ay del día! porque cercano está el día de Jehová, y vendrá como destrucción por el Todopoderoso.  16 ¿No es quitado el mantenimiento de delante de nuestros ojos, la alegría y el placer de la casa de nuestro Dios?  17 El grano se pudrió debajo de sus terrones, los bastimentos fueron asolados, los alfolíes destruídos; porque se secó el trigo.  18 ¡Cuánto gimieron las bestias! ¡cuán turbados anduvieron los hatos de los bueyes, porque no tuvieron pastos! también fueron asolados los rebaños de las ovejas.  19 A ti, oh Jehová, clamaré: porque fuego consumió los pastos del desierto, y llama abrasó todos los árboles del campo.  20 Las bestias del campo bramarán también á ti; porque se secaron los arroyos de las aguas, y fuego consumió las praderías del desierto.$x$),
($c$Joel 2:30, 31$c$, $x$30 Y daré prodigios en el cielo y en la tierra, sangre, y fuego, y columnas de humo.  31 El sol se tornará en tinieblas, y la luna en sangre, antes que venga el día grande y espantoso de Jehová.$x$),
($c$Joel 3:15$c$, $x$El sol y la luna se oscurecerán, y las estrellas retraerán su resplandor.$x$),
($c$Josué 23:6$c$, $x$Esforzaos pues mucho á guardar y hacer todo lo que está escrito en el libro de la ley de Moisés, sin apartaros de ello ni á la diestra ni á la siniestra;$x$),
($c$Juan 10:10$c$, $x$El ladrón no viene sino para hurtar, y matar, y destruir: yo he venido para que tengan vida, y para que la tengan en abundancia.$x$),
($c$Juan 10:30$c$, $x$Yo y el Padre una cosa somos.$x$),
($c$Juan 10:30-33$c$, $x$30 Yo y el Padre una cosa somos.  31 Entonces volvieron á tomar piedras los Judíos para apedrearle.  32 Respondióles Jesús: Muchas buenas obras os he mostrado de mi Padre; ¿por cuál obra de esas me apedreáis?  33 Respondiéronle los Judíos, diciendo: Por buena obra no te apedreamos, sino por la blasfemia; y porque tú, siendo hombre, te haces Dios.$x$),
($c$Juan 11:11$c$, $x$Dicho esto, díceles después: Lázaro nuestro amigo duerme; mas voy á despertarle del sueño.$x$),
($c$Juan 11:24$c$, $x$Marta le dice: Yo sé que resucitará en la resurrección en el día postrero.$x$),
($c$Juan 14:1-3$c$, $x$1 No se turbe vuestro corazón: creéis en Dios, creed también en mí.  2 En la casa de mi Padre muchas moradas hay: de otra manera os lo hubiera dicho: voy, pues, á preparar lugar para vosotros.  3 Y si me fuere, y os aparejare lugar, vendré otra vez, y os tomaré á mí mismo: para que donde yo estoy, vosotros también estéis.$x$),
($c$Juan 14:15, 16$c$, $x$15 Si me amáis, guardad mis mandamientos;  16 Y yo rogaré al Padre, y os dará otro Consolador, para que esté con vosotros para siempre:$x$),
($c$Juan 14:17$c$, $x$Al Espíritu de verdad, al cual el mundo no puede recibir, porque no le ve, ni le conoce: mas vosotros le conocéis; porque está con vosotros, y será en vosotros.$x$),
($c$Juan 14:2, 3$c$, $x$2 En la casa de mi Padre muchas moradas hay: de otra manera os lo hubiera dicho: voy, pues, á preparar lugar para vosotros.  3 Y si me fuere, y os aparejare lugar, vendré otra vez, y os tomaré á mí mismo: para que donde yo estoy, vosotros también estéis.$x$),
($c$Juan 14:26$c$, $x$Mas el Consolador, el Espíritu Santo, al cual el Padre enviará en mi nombre, él os enseñará todas las cosas, y os recordará todas las cosas que os he dicho.$x$),
($c$Juan 16:13$c$, $x$Pero cuando viniere aquel Espíritu de verdad, él os guiará á toda verdad; porque no hablará de sí mismo, sino que hablará todo lo que oyere, y os hará saber las cosas que han de venir.$x$),
($c$Juan 17:17$c$, $x$Santifícalos en tu verdad: tu palabra es verdad.$x$),
($c$Juan 17:5$c$, $x$Ahora pues, Padre, glorifícame tú cerca de ti mismo con aquella gloria que tuve cerca de ti antes que el mundo fuese.$x$),
($c$Juan 1:1, 14$c$, $x$1 En el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios.  14 Y aquel Verbo fué hecho carne, y habitó entre nosotros (y vimos su gloria, gloria como del unigénito del Padre), lleno de gracia y de verdad.$x$),
($c$Juan 1:1-3$c$, $x$1 En el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios.  2 Este era en el principio con Dios.  3 Todas las cosas por él fueron hechas; y sin él nada de lo que es hecho, fué hecho.$x$),
($c$Juan 1:1-3, 10, 14$c$, $x$1 En el principio era el Verbo, y el Verbo era con Dios, y el Verbo era Dios.  2 Este era en el principio con Dios.  3 Todas las cosas por él fueron hechas; y sin él nada de lo que es hecho, fué hecho.  10 En el mundo estaba, y el mundo fué hecho por él; y el mundo no le conoció.  14 Y aquel Verbo fué hecho carne, y habitó entre nosotros (y vimos su gloria, gloria como del unigénito del Padre), lleno de gracia y de verdad.$x$),
($c$Juan 1:3$c$, $x$Todas las cosas por él fueron hechas; y sin él nada de lo que es hecho, fué hecho.$x$),
($c$Juan 1:3, 10, 14$c$, $x$3 Todas las cosas por él fueron hechas; y sin él nada de lo que es hecho, fué hecho.  10 En el mundo estaba, y el mundo fué hecho por él; y el mundo no le conoció.  14 Y aquel Verbo fué hecho carne, y habitó entre nosotros (y vimos su gloria, gloria como del unigénito del Padre), lleno de gracia y de verdad.$x$),
($c$Juan 1:42$c$, $x$Y le trajo á Jesús. Y mirándole Jesús, dijo: Tú eres Simón, hijo de Jonás: tú serás llamado Cephas (que quiere decir, Piedra).$x$),
($c$Juan 20:27$c$, $x$Luego dice á Tomás: Mete tu dedo aquí, y ve mis manos: y alarga acá tu mano, y métela en mi costado: y no seas incrédulo, sino fiel.$x$),
($c$Juan 3:13$c$, $x$Y nadie subió al cielo, sino el que descendió del cielo, el Hijo del hombre, que está en el cielo.$x$),
($c$Juan 5:23$c$, $x$Para que todos honren al Hijo como honran al Padre. El que no honra al Hijo, no honra al Padre que le envió.$x$),
($c$Juan 5:28, 29$c$, $x$28 No os maravilléis de esto; porque vendrá hora, cuando todos los que están en los sepulcros oirán su voz;  29 Y los que hicieron bien, saldrán á resurrección de vida; mas los que hicieron mal, á resurrección de condenación.$x$),
($c$Juan 5:39$c$, $x$Escudriñad las Escrituras, porque á vosotros os parece que en ellas tenéis la vida eterna; y ellas son las que dan testimonio de mí.$x$),
($c$Juan 8:44$c$, $x$Vosotros de vuestro padre el diablo sois, y los deseos de vuestro padre queréis cumplir. El, homicida ha sido desde el principio, y no permaneció en la verdad, porque no hay verdad en él. Cuando habla mentira, de suyo habla; porque es mentiroso, y padre de mentira.$x$),
($c$Juan 8:56$c$, $x$Abraham vuestro padre se gozó por ver mi día; y lo vió, y se gozó.$x$),
($c$Judas 14:15$c$, $x$14 De los cuales también profetizó Enoc, séptimo desde Adam, diciendo: He aquí, el Señor es venido con sus santos millares,  15 A hacer juicio contra todos, y á convencer á todos los impíos de entre ellos tocante á todas sus obras de impiedad que han hecho impíamente, y á todas las cosas duras que los pecadores impíos han hablado contra él.$x$),
($c$Levítico 1:1, 2$c$, $x$1 Y llamó Jehová á Moisés, y habló con él desde el tabernáculo del testimonio, diciendo:  2 Habla á los hijos de Israel, y diles: Cuando alguno de entre vosotros ofreciere ofrenda á Jehová, de ganado vacuno ú ovejuno haréis vuestra ofrenda.$x$),
($c$Levítico 23:24, 27, 32, 39$c$, $x$24 Habla á los hijos de Israel, y diles: En el mes séptimo, al primero del mes tendréis sábado, una conmemoración al son de trompetas, y una santa convocación.  27 Empero á los diez de este mes séptimo será el día de las expiaciones: tendréis santa convocación, y afligiréis vuestras almas, y ofreceréis ofrenda encendida á Jehová.  32 Sábado de reposo será á vosotros, y afligiréis vuestras almas, comenzando á los nueve del mes en la tarde: de tarde á tarde holgaréis vuestro sábado.  39 Empero á los quince del mes séptimo, cuando hubiereis allegado el fruto de la tierra, haréis fiesta á Jehová por siete días: el primer día será sábado; sábado será también el octavo día.$x$),
($c$Levítico 23:37, 38$c$, $x$37 Estas son las solemnidades de Jehová, á las que convocaréis santas reuniones, para ofrecer ofrenda encendida á Jehová, holocausto y presente, sacrificio y libaciones, cada cosa en su tiempo:  38 Además de los sábados de Jehová y además de vuestros dones, y á más de todos vuestros votos, y además de todas vuestras ofrendas voluntarias, que daréis á Jehová.$x$),
($c$Levítico 7:37, 38$c$, $x$37 Esta es la ley del holocausto, del presente, de la expiación por el pecado, y de la culpa, y de las consagraciones, y del sacrificio de las paces:  38 La cual intimó Jehová á Moisés, en el monte de Sinaí, el día que mandó á los hijos de Israel que ofreciesen sus ofrendas á Jehová en el desierto de Sinaí.$x$),
($c$Lucas 10:1$c$, $x$Y después de estas cosas, designó el Señor aun otros setenta, los cuales envió de dos en dos delante de sí, á toda ciudad y lugar á donde él había de venir.$x$),
($c$Lucas 10:18$c$, $x$Y les dijo: Yo veía á Satanás, como un rayo, que caía del cielo.$x$),
($c$Lucas 10:7$c$, $x$Y posad en aquella misma casa, comiendo y bebiendo lo que os dieren; porque el obrero digno es de su salario. No os paséis de casa en casa.$x$),
($c$Lucas 11:28$c$, $x$Y él dijo: Antes bienaventurados los que oyen la palabra de Dios, y la guardan.$x$),
($c$Lucas 14:14$c$, $x$Y serás bienaventurado; porque no te pueden retribuir; mas te será recompensado en la resurrección de los justos.$x$),
($c$Lucas 17:26-30$c$, $x$26 Y como fué en los días de Noé, así también será en los días del Hijo del hombre.  27 Comían, bebían, los hombres tomaban mujeres, y las mujeres maridos, hasta el día que entró Noé en el arca; y vino el diluvio, y destruyó á todos.  28 Asimismo también como fué en los días de Lot; comían, bebían, compraban, vendían, plantaban, edificaban;  29 Mas el día que Lot salió de Sodoma, llovió del cielo fuego y azufre, y destruyó á todos:  30 Como esto será el día en que el Hijo del hombre se manifestará.$x$),
($c$Lucas 18:7$c$, $x$¿Y Dios no hará justicia á sus escogidos, que claman á él día y noche, aunque sea longánime acerca de ellos?$x$),
($c$Lucas 1:26-28, 35$c$, $x$26 Y al sexto mes, el ángel Gabriel fué enviado de Dios á una ciudad de Galilea, llamada Nazaret,  27 A una virgen desposada con un varón que se llamaba José, de la casa de David: y el nombre de la virgen era María.  28 Y entrando el ángel á donde estaba, dijo, ¡Salve, muy favorecida! el Señor es contigo: bendita tú entre las mujeres.  35 Y respondiendo el ángel le dijo: El Espíritu Santo vendrá sobre ti, y la virtud del Altísimo te hará sombra; por lo cual también lo Santo que nacerá, será llamado Hijo de Dios.$x$),
($c$Lucas 1:35$c$, $x$Y respondiendo el ángel le dijo: El Espíritu Santo vendrá sobre ti, y la virtud del Altísimo te hará sombra; por lo cual también lo Santo que nacerá, será llamado Hijo de Dios.$x$),
($c$Lucas 1:70$c$, $x$Como habló por boca de sus santos profetas que fueron desde el principio:$x$),
($c$Lucas 20:46, 47$c$, $x$46 Guardaos de los escribas, que quieren andar con ropas largas, y aman las salutaciones en las plazas, y las primeras sillas en las sinagogas, y los primeros asientos en las cenas;  47 Que devoran las casas de las viudas, poniendo por pretexto la larga oración: éstos recibirán mayor condenación.$x$),
($c$Lucas 21:25, 26$c$, $x$25 Entonces habrá señales en el sol, y en la luna, y en las estrellas; y en la tierra angustia de gentes por la confusión del sonido de la mar y de las ondas:  26 Secándose los hombres á causa del temor y expectación de las cosas que sobrevendrán á la redondez de la tierra: porque las virtudes de los cielos serán conmovidas.$x$),
($c$Lucas 21:28$c$, $x$Y cuando estas cosas comenzaren á hacerse, mirad, y levantad vuestras cabezas, porque vuestra redención está cerca.$x$),
($c$Lucas 23:56$c$, $x$Y vueltas, aparejaron drogas aromáticas y ungüentos; y reposaron el sábado, conforme al mandamiento.$x$),
($c$Lucas 24:27$c$, $x$Y comenzando desde Moisés, y de todos los profetas, declarábales en todas las Escrituras lo que de él decían.$x$),
($c$Lucas 24:44$c$, $x$Y él les dijo: Estas son las palabras que os hablé, estando aún con vosotros: que era necesario que se cumpliesen todas las cosas que están escritas de mí en la ley de Moisés, y en los profetas, y en los salmos.$x$)
