Manda un mensaje diciendo: Si alguno adora a la bestia y a su imagen, y toma la señal, Tendrá que sufrir la ira de Dios, las siete postreras plagas”. (Apocalipsis 14: 6-10).$in$, '2026-2'),
(19, '2026-11-07', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$¿Qué es el hombre?$t$, NULL, $vc$Salmos 8:5$vc$, $vt$Pues le has hecho poco menor que los ángeles, y coronástelo de gloria y de lustre.$vt$, $in$El hombre fue creado a Imagen y Semejanza de Dios, pero fue hecho menos que los Ángeles que son seres Espirituales al servicio del Ser Supremo a favor del hombre que fue creado bueno y justo, dotado de inteligencia, conciencia y libre albedrío, de manera que pudiera ejercer dominio sobre los seres vivientes de la tierra.$in$, '2026-2'),
(20, '2026-11-14', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La naturaleza del hombre$t$, NULL, $vc$1 Tesalonicenses 5:23$vc$, $vt$Y el Dios de paz os santifique en todo; para que vuestro espíritu y alma y cuerpo sea guardado entero sin reprensión para la venida de nuestro Señor Jesucristo.$vt$, $in$El Espíritu, es el aliento de vida, el alma es el hombre interior y el cuerpo es la materia que fue formada del polvo de la tierra.$in$, '2026-2'),
(21, '2026-11-21', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$¿Dónde están los muertos?$t$, NULL, $vc$1 Tesalonicenses 4:13$vc$, $vt$Tampoco, hermanos, queremos que ignoréis acerca de los que duermen, que no os entristezcáis como los otros que no tienen esperanza.$vt$, $in$Quiere el Seño r que conozcamos en que condición queda el hombre en la muerte. Esta muerte es comparada a un sueño profundo. En ella no se nota el transcurso del tiempo.$in$, '2026-2'),
(22, '2026-11-28', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Satanás$t$, NULL, $vc$1 Pedro 5:8$vc$, $vt$Sed templados, y velad; porque vuestro adversario el diablo, cual león rugiente, anda alrededor buscando á quien devore:$vt$, $in$Satanás o Satán significa ADVERSARIO, y de ahí se emplea particularmente esa palabra para indicar el gran enemigo de las almas, el diablo, príncipe de los ángeles caídos.$in$, '2026-2'),
(23, '2026-12-05', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La verdadera Iglesia según las Escrituras$t$, NULL, $vc$Hechos 4:12$vc$, $vt$Y en ningún otro hay salud; porque no hay otro nombre debajo del cielo, dado á los hombres, en que podamos ser salvos.$vt$, $in$Hay muchas iglesias en nuestros días y cada una de ellas sostiene ser la verdadera. Lógicamente no se puede aceptar como verdadera la iglesia que no está de acuerdo con las doctrinas del Nuevo Testamento.$in$, '2026-2'),
(24, '2026-12-12', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$La organización de la Iglesia$t$, NULL, $vc$Romanos 16:16$vc$, $vt$Saludaos los unos á los otros con ósculo santo. Os saludan todas las iglesias de Cristo.$vt$, $in$La Iglesia de Cristo Restaurada del Séptimo Día, no es una organización, sino un organismo, pues en cada uno de sus miembros palpita la vida de Nuestro Señor Jesucristo, el cual dirige el movimiento de todo el cuerpo en general y de cada miembro en particular.$in$, '2026-2'),
(25, '2026-12-19', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Cristo y Pedro$t$, NULL, $vc$Mateo 16:18$vc$, $vt$Mas yo también te digo, que tú eres Pedro, y sobre esta piedra edificaré mi iglesia; y las puertas del infierno no prevalecerán contra ella.$vt$, $in$Los Cristianos afirmamos que esta PIEDRA es un ser Divino; los católicos romanos alegan que esta PIEDRA es un ser humano. Alegan que es Pedro. Nosotros afirmamos que es Cristo, la gran Roca Eterna.$in$, '2026-2'),
(26, '2026-12-26', $s$La doctrina pura de las Sagradas Escrituras$s$, $t$Si, la predicación del Evangelio es gratuita$t$, NULL, $vc$Isaías 52:3$vc$, $vt$Porque así dice Jehová: De balde fuisteis vendidos; por tanto, sin dinero seréis rescatados.$vt$, $in$Si Cristo entrara en los templos de las Iglesias populares de nuestros días, y viese el comercio impío que se practica en el nombre de Dios, ¿No arrojaría acaso a esos profanadores, como arrojo del Templo a los mercaderes de su tiempo?$in$, '2026-2')
on conflict (fecha) do update set numero=excluded.numero, serie=excluded.serie, titulo=excluded.titulo, lectura_biblica=excluded.lectura_biblica, versiculo_central_cita=excluded.versiculo_central_cita, versiculo_central_texto=excluded.versiculo_central_texto, introduccion=excluded.introduccion, semestre=excluded.semestre;
-- @@
delete from lecciones_preguntas where leccion_id in (select id from lecciones where fecha in ('2026-07-04','2026-07-11','2026-07-18','2026-07-25','2026-08-01','2026-08-08','2026-08-15','2026-08-22','2026-08-29','2026-09-05','2026-09-12','2026-09-19','2026-09-26','2026-10-03','2026-10-10','2026-10-17','2026-10-24','2026-10-31','2026-11-07','2026-11-14','2026-11-21','2026-11-28','2026-12-05','2026-12-12','2026-12-19','2026-12-26'));
select l.id, p.orden, p.pregunta, p.citas, p.nota from (values
('2026-07-04', 1, $q$¿Qué nombre se da a los escritos de la Biblia?$q$, ARRAY['Mateo 21:42']::text[], NULL),
('2026-07-04', 2, $q$¿Por qué los hombres tuercen la palabra de Dios?$q$, ARRAY['Marcos 12:24']::text[], NULL),
('2026-07-04', 3, $q$¿Cómo fueron dadas las Escrituras?$q$, ARRAY['2 Timoteo 3:16']::text[], NULL),
('2026-07-04', 4, $q$¿Qué otro nombre se le dan a las Escrituras?$q$, ARRAY['Lucas 8:21']::text[], NULL),
('2026-07-04', 5, $q$¿Quién dirigió a los hombres que hablaban en nombre de Dios?$q$, ARRAY['2 Pedro 1:21']::text[], NULL),
('2026-07-04', 6, $q$¿Con qué fin fueron escritas las Escrituras?$q$, ARRAY['Romanos 15:4']::text[], NULL),
('2026-07-04', 7, $q$¿Para qué sirven las Escrituras?$q$, ARRAY['2 Timoteo 3:16']::text[], NULL),
('2026-07-04', 8, $q$¿Qué dijo Cristo a los judíos acerca del estudio de las Escrituras?$q$, ARRAY['Juan 5:39']::text[], NULL),
('2026-07-04', 9, $q$¿Cómo probó Cristo su carácter de Mesías?$q$, ARRAY['Lucas 24:27']::text[], NULL),
('2026-07-04', 10, $q$¿Cuánto del antiguo testamento revela lo concerniente a Cristo?$q$, ARRAY['Lucas 24:44']::text[], NULL),
('2026-07-04', 11, $q$¿Qué quería el Señor que su palabra fuese para nosotros en un mundo de tinieblas, de pecado y muerte?$q$, ARRAY['Salmos 119:105']::text[], NULL),
('2026-07-04', 12, $q$¿Qué puede hacer en el hombre la palabra de Dios, y qué es ésta?$q$, ARRAY['Juan 17:17']::text[], NULL),
('2026-07-04', 13, $q$¿Por qué se tuercen las Escrituras?$q$, ARRAY['Mateo 22:29']::text[], NULL),
('2026-07-04', 14, $q$¿Quién nos ayuda y nos guía en el estudio de las Escrituras?$q$, ARRAY['Juan 14:26','Juan 16:13']::text[], NULL),
('2026-07-04', 15, $q$¿Cómo podemos recibir su ayuda? ¿Qué parte desempeña Cristo?$q$, ARRAY['Juan 14:15, 16']::text[], NULL),
('2026-07-04', 16, $q$¿Cuál es uno de los nombres del Espíritu Santo?$q$, ARRAY['Juan 14:17']::text[], NULL),
('2026-07-04', 17, $q$¿Quién envía a los que enseñan la verdad?$q$, ARRAY['Hechos 13:2, 4','Romanos 10:15']::text[], NULL),
('2026-07-04', 18, $q$¿A quién declaro Cristo bienaventurado?$q$, ARRAY['Lucas 11:28']::text[], NULL),
('2026-07-11', 1, $q$¿Cómo se refirió Cristo a la Eternidad de su existencia?$q$, ARRAY['Juan 17:5']::text[], NULL),
('2026-07-11', 2, $q$¿Qué se dice de la preexistencia del niño mesías que debía nacer en Belén?$q$, ARRAY['Miqueas 5:2']::text[], NULL),
('2026-07-11', 3, $q$¿Cómo fue engendrado Cristo en la carne?$q$, ARRAY['Lucas 1:35']::text[], NULL),
('2026-07-11', 4, $q$¿Qué pasaje de la Escritura declara que el hijo de Dios vino a vivir en forma humana?$q$, ARRAY['Juan 1:1, 14']::text[], NULL),
('2026-07-11', 5, $q$¿En qué consiste, según la declaración de Cristo, su relación con el Padre?$q$, ARRAY['Juan 10:30']::text[], NULL),
('2026-07-11', 6, $q$¿Qué profecía fue hecha acerca de su nacimiento?$q$, ARRAY['Isaías 7:14','Mateo 1:22, 23']::text[], NULL),
('2026-07-11', 7, $q$¿Cómo se cumplió esta predicción notable?$q$, ARRAY['Lucas 1:26-28, 35']::text[], NULL),
('2026-07-11', 8, $q$¿Qué declaración fue hecha en ocasión de su nacimiento?$q$, ARRAY['Lucas 2:10-14']::text[], NULL),
('2026-07-11', 9, $q$¿Cómo fue reconocido Cristo por su Padre mientras vivía en la tierra?$q$, ARRAY['Mateo 3:17']::text[], NULL),
('2026-07-11', 10, $q$¿Qué demuestra que Cristo sostiene con los ángeles la misma relación que el Padre?$q$, ARRAY['Mateo 16:27','Mateo 24:31']::text[], NULL),
('2026-07-11', 11, $q$Los hijos Redimidos de Dios, los Elegidos, pertenecen al Padre y al Hijo.$q$, ARRAY['Lucas 18:7','Mateo 24:31']::text[], NULL),
('2026-07-11', 12, $q$El Padre y el Hijo participan igualmente en la entrega de las recompensas finales.$q$, ARRAY['Hebreos 11:6','Mateo 16:27']::text[], NULL),
('2026-07-11', 13, $q$¿Quién fue el agente activo en la creación de todas las cosas?$q$, ARRAY['Salmos 36:6, 9','Hebreos 1:1, 2','Juan 1:1-3']::text[], $n$Todo fue hecho por Él, el Hijo.$n$),
('2026-07-11', 14, $q$Cuando Jesús dijo: “El sábado por causa del hombre es hecho” y “El hijo del hombre es Señor aún del Sábado” ¿Por qué era Señor del Sábado?$q$, ARRAY['Marcos 2:27, 28']::text[], $n$Porque lo hizo todo, y el Sábado fue hecho y bendecido en honor de la creación.$n$),
('2026-07-11', 15, $q$Teniendo un Salvador tan admirable ¿Qué se nos dice que debemos hacer?$q$, ARRAY['Heb. 4:14, 15']::text[], NULL),
('2026-07-18', 1, $q$La profecía es algo más seguro que nuestros sentidos.$q$, ARRAY['2 Pedro 1:16-19']::text[], NULL),
('2026-07-18', 2, $q$El propósito u objeto de la profecía es iluminarnos y llevarnos a Cristo y su reino.$q$, ARRAY['Hechos 26:22-29']::text[], NULL),
('2026-07-18', 3, $q$Atestigua el gran amor de Dios hacia su pueblo.$q$, ARRAY['Amos 3:7']::text[], NULL),
('2026-07-18', 4, $q$Uno de los fines de la profecía es ponernos en armonía con la Ley de Dios.$q$, ARRAY['Deuteronomio 29:29']::text[], NULL),
('2026-07-18', 5, $q$La luz de la profecía fué encendida al comenzar la historia del mundo.$q$, ARRAY['Hechos 3:21','Lucas 1:70']::text[], NULL),
('2026-07-18', 6, $q$Enoc, de la séptima generación después de Adán, profetizó acerca de la venida de Cristo y la Restauración de su Reino.$q$, ARRAY['Judas 14:15']::text[], NULL),
('2026-07-18', 7, $q$El Rey de Reyes y su Reino fueron revelados a Abraham.$q$, ARRAY['Juan 8:56','Hebreos 11:8-16']::text[], NULL),
('2026-07-18', 8, $q$Job vió la venida del Redentor.$q$, ARRAY['Job 19:23-27']::text[], NULL),
('2026-07-18', 9, $q$Tanto David como Isaías profetizaron la Venida de Cristo.$q$, ARRAY['Salmos 50:3-5','Isaías 25:8','Isaías 25:9']::text[], NULL),
('2026-07-18', 10, $q$¿Hasta cuándo debía quedar sellada la profecía de Daniel?$q$, ARRAY['Daniel 12:4']::text[], NULL),
('2026-07-18', 11, $q$¿Qué seguridad dio el Ángel de que esas profecías serían comprendidas en los postreros tiempos?$q$, ARRAY['Daniel 12:9','Daniel 12:10','Daniel 12:4']::text[], NULL),
('2026-07-18', 12, $q$¿Cómo se llama el último libro de la Biblia?$q$, ARRAY['Apocalipsis 1:1']::text[], NULL),
('2026-07-18', 13, $q$¿Qué se dice de aquellos que leen, oyen y guardan las cosas contenidas en ese libro?$q$, ARRAY['Apocalipsis 1:3']::text[], $n$Es realmente asombroso, como hemos visto ya, la exactitud con que fueron revelados a los Profetas los acontecimientos que se están registrando, siglos antes de que acontecieran, por decirlo así, la historia de la humanidad.$n$),
('2026-07-25', 1, $q$¿Cuáles fueron algunos de los acontecimientos que predijo el Señor?$q$, ARRAY['Mateo 24:6, 7']::text[], NULL),
('2026-07-25', 2, $q$Según Lucas, ¿Cómo contestó a la pregunta de los discípulos?$q$, ARRAY['Lucas 21:25, 26']::text[], $n$Este es un cuadro exacto de las condiciones que reinan en el mundo hoy. Por la codicia, la inmoralidad, las dificultades entre el capital y el trabajo, los preparativos bélicos, las naciones y los hombres se sienten perplejos.$n$),
('2026-07-25', 3, $q$¿Qué señales dijo Cristo que habría en el cielo?$q$, ARRAY['Mateo 24:29']::text[], NULL),
('2026-07-25', 4, $q$En el Antiguo Testamento, ¿Qué señales dió Joel del tiempo del fin?$q$, ARRAY['Joel 2:30, 31','Joel 3:15']::text[], NULL),
('2026-07-25', 5, $q$La ciencia y el mucho viajar sería otra señal.$q$, ARRAY['Daniel 12:4']::text[], $n$Se han construído en todas las naciones grandes redes de carreteras para viajar en grandes cantidades los hombres, por medio de automóviles y autobuses, se han construído grandes aviones para surcar los mares y la ciencia se ha multiplicado.$n$),
('2026-07-25', 6, $q$¿Qué se dice de los acontecimientos comerciales e industriales?$q$, ARRAY['Amos 8:4-6','Santiago 5:1-4','Apocalipsis 18:11, 23']::text[], NULL),
('2026-07-25', 7, $q$¿Qué se dice que acontecerá con los que gobiernan a los pueblos?$q$, ARRAY['Jeremías 13:18']::text[], NULL),
('2026-07-25', 8, $q$Los actuales gobiernos del mundo se están armando en grande manera, y sin embargo, dicen paz y seguridad.$q$, ARRAY['1 Tesalonicenses 5:1-4']::text[], NULL),
('2026-07-25', 9, $q$Pero camino de paz, no lo conocen.$q$, ARRAY['Romanos 3:13-18']::text[], NULL),
('2026-07-25', 10, $q$¿Cuál es la condición de la sociedad actual y su peligro?$q$, ARRAY['Lucas 17:26-30']::text[], NULL),
('2026-07-25', 11, $q$Se profetizó, que en el tiempo del fin, el ambiente religioso estaría completamente corrompido.$q$, ARRAY['Apocalipsis 3:14-17','2 Timoteo 4:3, 4']::text[], NULL),
('2026-07-25', 12, $q$En virtud de que los malos hombres y los engañadores se han multiplicado en el mundo, ¿Qué acontecerá con ellos?$q$, ARRAY['2 Timoteo 3:13']::text[], NULL),
('2026-07-25', 13, $q$En vista de estas condiciones, ¿Qué se nos aconseja que hagamos?$q$, ARRAY['Lucas 21:28','Mateo 24:44']::text[], NULL),
('2026-08-01', 1, $q$¿Qué promesa hizo Cristo mismo acerca de su venida?$q$, ARRAY['Juan 14:1-3']::text[], NULL),
('2026-08-01', 2, $q$Enoc anunció la segunda venida de Cristo.$q$, ARRAY['Judas 14:15']::text[], NULL),
('2026-08-01', 3, $q$¿Cómo se fue Cristo de este mundo, y cómo volverá?$q$, ARRAY['Hechos 1:9-11']::text[], NULL),
('2026-08-01', 4, $q$¿Era Cristo realmente una persona después de su resurrección?$q$, ARRAY['Juan 20:27']::text[], NULL),
('2026-08-01', 5, $q$¿Será este mismo Jesús una persona real y visible cuando vuelva?$q$, ARRAY['Hech. 1:11','Apoc. 1:7']::text[], NULL),
('2026-08-01', 6, $q$¿Vendrá realmente Cristo mismo y lo sabrá el mundo?$q$, ARRAY['1 Tesalonicenses 4:16']::text[], NULL),
('2026-08-01', 7, $q$¿Qué sucederá a los justos muertos y a los justos que esten viviendo cuando venga Cristo?$q$, ARRAY['1 Tesalonicenses 4:17, 18']::text[], NULL),
('2026-08-01', 8, $q$¿Cómo afectará la venida de Cristo al pecado y a los pecadores?$q$, ARRAY['2 Tesalonicenses 1:7-9','Apocalipsis 6:14-17']::text[], NULL),
('2026-08-01', 9, $q$¿En qué consistía la esperanza del apóstol Pablo mientras vivía y trabajaba en este mundo de pecado?$q$, ARRAY['Tito 2:13','2 Timoteo 4:6-8']::text[], NULL),
('2026-08-01', 10, $q$¿Cuándo serán los Santos como Jesús?$q$, ARRAY['1 Juan 3:2']::text[], NULL),
('2026-08-01', 11, $q$¿Cuándo serán reunidos los escogidos de Dios? ¿Sucederá esto en el silencio y en secreto?$q$, ARRAY['Mateo 24:30, 31','1 Tesalonicenses 4:16, 17']::text[], NULL),
('2026-08-01', 12, $q$¿Cuándo serán transformados los hijos de Dios de seres mortales a inmortales?$q$, ARRAY['1 Corintios 15:51-53']::text[], NULL),
('2026-08-01', 13, $q$¿Cuántos recibirán la recompensa cuando venga Cristo?$q$, ARRAY['Mateo 16:27']::text[], NULL),
('2026-08-01', 14, $q$¿Qué dice él que traerá consigo cuando venga?$q$, ARRAY['Apocalipsis 22:12','Lucas 14:14']::text[], NULL),
('2026-08-01', 15, $q$Cuando Cristo venga a recoger a sus escogidos, ¿A dónde los transportará?$q$, ARRAY['Mateo 13:24-30','Gálatas 4:26','Hebreos 12:22']::text[], $n$Una secta religiosa asegura que los escogidos serán llevados a la Jerusalén terrenal.$n$),
('2026-08-01', 16, $q$¿Qué es necesario que hagamos si queremos estar entre los ángeles en la Patria Celestial?$q$, ARRAY['Apocalipsis 22:14','Hebreos 11:14-16']::text[], NULL),
('2026-08-08', 1, $q$Cristo aseguro a los Apóstoles que iba al cielo a preparar moradas.$q$, ARRAY['Juan 14:1-3']::text[], NULL),
('2026-08-08', 2, $q$Hasta ahora nadie ha subido al tercer cielo, sino únicamente Cristo$q$, ARRAY['Juan 3:13']::text[], NULL),
('2026-08-08', 3, $q$Mientras peregrinamos en esta tierra, tenemos mucho por qué gozarnos y alegrarnos, pues sabemos que iremos a la Patria Celestial. (Mateo 5:12). LA MERCED GRANDE, significa pago retribución.$q$, ARRAY['Mateo 5:12']::text[], NULL),
('2026-08-08', 4, $q$Los verdaderos seguidores de Cristo serán ARREBATADOS en las nubes a recibirle.$q$, ARRAY['1 Tesalonicenses 4:17']::text[], NULL),
('2026-08-08', 5, $q$Los redimidos serán ARREBATADOS por los Ángeles.$q$, ARRAY['Mateo 24:30, 31','Marcos 13:26, 27']::text[], NULL),
('2026-08-08', 6, $q$Otro nombre que también se da al ARREBATAMIENTO es el de RECOGIMIENTO A ÉL.$q$, ARRAY['2 Tesalonicenses 2:1, 2']::text[], NULL),
('2026-08-08', 7, $q$Cuando Cristo venga, será para tener nuestra vivienda en los cielos según su promesa.$q$, ARRAY['Filipenses 3:20,21']::text[], NULL),
('2026-08-08', 8, $q$Para ir a los cielos tiene que verificarse una transformación corporal.$q$, ARRAY['1 Corintios 15:49-53']::text[], NULL),
('2026-08-08', 9, $q$La esperanza del verdadero Cristiano es el ser sobrevestido de cuerpo Celestial.$q$, ARRAY['2 Corintios 5:24']::text[], NULL),
('2026-08-08', 10, $q$La vocación de los Santos que durmieron y la nuestra es la  Patria Celestial.$q$, ARRAY['Hebreos 3:1','Hebreos 13:14']::text[], NULL),
('2026-08-08', 11, $q$Los redimidos de todas las razas y de todas las lenguas estarán en el cielo.$q$, ARRAY['Apocalipsis 7:9']::text[], NULL),
('2026-08-08', 12, $q$El apóstol Pablo nos indica que el REINO DE CRISTO será en el tercer cielo.$q$, ARRAY['2 Corintios 12:2-4','2 Timoteo 4:18']::text[], $n$Este tercer cielo que el Apóstol Pablo nos describe, equivale al CIELO DE LOS CIELOS. (Deuteronomio 10: 14). Los más altos cielos que contienen la ADMOSFERA y del cielo SIDERAL.$n$),
('2026-08-15', 1, $q$La tierra la formó Dios para ser habitada.$q$, ARRAY['Isaías 45:18']::text[], NULL),
('2026-08-15', 2, $q$¿Será la tierra siempre como la conocemos?$q$, ARRAY['Isaías 65:17','Apocalipsis 22:1']::text[], NULL),
('2026-08-15', 3, $q$¿Quiénes habitarán esta Tierra Nueva?$q$, ARRAY['Mateo 5:5','Salmos 37:11']::text[], NULL),
('2026-08-15', 4, $q$¿A qué tendrán derecho los habitantes de la tierra nueva?$q$, ARRAY['Isaías 66:22']::text[], NULL),
('2026-08-15', 5, $q$¿Qué harán en la tierra nueva?$q$, ARRAY['Isaías 66:23']::text[], NULL),
('2026-08-15', 6, $q$En el principio ¿Quién dominaba al mundo?$q$, ARRAY['Génesis 1:26-28']::text[], NULL),
('2026-08-15', 7, $q$¿Por qué perdió el hombre su dominio?$q$, ARRAY['Génesis 3:1-6']::text[], NULL),
('2026-08-15', 8, $q$¿Qué tierra fue prometida a Abraham  y a nosotros mediante Cristo?$q$, ARRAY['Romanos 4:13','Gálatas 3:16, 29']::text[], $n$En la Nueva Tierra y en la  Nueva Jerusalén era donde Abraham el Padre  de los fieles, esperaba recibir la heredad Eterna, prometida a él y a su simiente. Y allí hallarán su heredad todos los verdaderos Cristianos.$n$),
('2026-08-15', 9, $q$Los impíos poseen ahora la tierra, pero el pueblo de Dios no recibirá la Tierra Nueva hasta que los impíos estén cortados o destruidos.$q$, ARRAY['Salmos  37:34']::text[], NULL),
('2026-08-15', 10, $q$¿Qué pasará con los que temen el nombre de Dios en la Tierra Nueva?$q$, ARRAY['2 Pedro 3:13','Malaquías 4:2, 3']::text[], NULL)
) as p(fecha, orden, pregunta, citas, nota) join lecciones l on l.fecha = p.fecha::date;
-- @@
