select l.id, p.orden, p.pregunta, p.citas, p.nota from (values
('2026-10-03', 9, $q$¿Cuánta honra se debe a Cristo?$q$, ARRAY['Juan 5:23','Juan 10:30']::text[], $n$Al observar el sábado honramos pues a Cristo tanto como al Padre.$n$),
