('2026-11-07', 6, $q$¿Cómo se define la naturaleza del hombre?$q$, ARRAY['Romanos 6:12']::text[], $n$Mortal: sujeto a la muerte.$n$),
('2026-11-07', 7, $q$¿Cuál es la naturaleza de Dios?$q$, ARRAY['1 Timoteo 1:17']::text[], $n$Inmortal: Exento de toda posibilidad de morir.$n$),
