('2026-11-14', 6, $q$Al morir, el hombre vuelve a donde estaba.$q$, ARRAY['Génesis 3:19']::text[], NULL),
('2026-11-14', 7, $q$El Espíritu, o aliento de vida, vuelve a Dios quien lo dió, no así el alma, esa queda inconsciente hasta la venida de Cristo.$q$, ARRAY['Eclesiastés 12:7']::text[], NULL),
