('2026-11-14', 11, $q$Sus pensamientos perecen en el día de su muerte.$q$, ARRAY['Salmos 146:4']::text[], NULL),
('2026-11-14', 12, $q$No saben absolutamente nada.$q$, ARRAY['Eclesiastés 9:5']::text[], NULL),
('2026-11-14', 13, $q$El hombre muere como los animales fraccionales.$q$, ARRAY['Eclesiastés 3:19']::text[], NULL),
